window.__dh_data["ku"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "دهاماپادا",
  "chaps": "بەشەکان",
  "fontsize": "قەبارەی فۆنت",
  "chap1": "کۆپلە دووانەکان",
  "1": "بیرکردنەوە و دەروونی مرۆڤ سەرچاوەی هەموو کارە خراپەکانە. بیرکردنەوە بنچینەیە؛ کارەکان لە بیرکردنەوەوە سەرچاوە دەگرن. ئەگەر کەسێک بە نیەت و بیرکردنەوەیەکی خراپەوە قسە بکات یان ڕەفتار بکات، ئازار و ناڕەحەتی شوێنی دەکەوێت، ڕێک وەک چۆن ویلی عارەبانە بە دوای ئەو گایەدا دەڕوات کە ڕایکێشاوە.",
  "2": "بیرکردنەوە و دەروونی مرۆڤ سەرچاوەی هەموو کارە باشەکانە. بیرکردنەوە بنچینەیە؛ کارەکان لە بیرکردنەوەوە سەرچاوە دەگرن. ئەگەر کەسێک بە نیەت و بیرکردنەوەیەکی پاکەوە قسە بکات یان ڕەفتار بکات، بەختەوەری شوێنی دەکەوێت، ڕێک وەک سێبەرەکەی کە هەرگیز لێی جیا نابێتەوە.",
  "3": "ئەو سووکایەتی پێکردم، لێیدام، بەسەرمدا سەرکەوت، ماڵی بردم، ئەوانەی بەردەوام ئەم بیرۆکانە لە مێشکیاندا دەهێڵنەوە، ڕق و کینە لە دڵیاندا دانامرکێتەوە.",
  "4": "ئەو سووکایەتی پێکردم، لێیدام، بەسەرمدا سەرکەوت، ماڵی بردم، ئەوانەی ئەم بیرۆکانە لە مێشکیاندا ناهێڵنەوە، ڕق و کینە لە دڵیاندا دادەمرکێتەوە.",
  "5": "لەم جیهانەدا، ڕق هەرگیز بە ڕق لەناو ناچێت؛ تەنها بە خۆشەویستی و لێبوردەیی لەناو دەچێت. ئەمە یاسایەکی نەگۆڕ و هەمیشەیییە.",
  "6": "خەڵکانی تر (ئەوانەی خەریکی کێشە و شەڕن) درک بەوە ناکەن کە بەهۆی ئەم ناکۆکییانەوە ژیانی خۆیان لەناو دەبەن و کاتیان بەفیڕۆ دەدەن؛ بەڵام ئەوانەی لەم ڕاستییە تێدەگەن، دەستبەجێ کۆتایی بە کێشە و دوژمنکارییەکانیان دەهێڵن.",
  "7": "هەر کەسێک تەنها خەریکی ڕامان و ڕاکردن بێت بەدوای چێژە کاتییەکاندا، کۆنترۆڵی حەزەکانی نەکات، لە خواردندا چاوچنۆک بێت، و تەمبەڵ و بێ بەرھەم بێت، ئەوا 'مارا' (هێزی شەڕ و سەرلێشێواوی) بە ئاسانی دەیکێشێت بە عەرزدا، ڕێک وەک چۆن با دارێکی لاواز ڕیشەکێش دەکات.",
  "8": "هەر کەسێک لە جیاتی چێژ، لە ڕاستی و لە کاتیبوونی شتەکان بکۆڵێتەوە، کۆنترۆڵی حەزەکانی بکات، لە خواردندا بە ئەندازە بێت، و خاوەن باوەڕ و هەوڵی بەردەوام بێت، ئەوا 'مارا' ناتوانێت بیبەزێنێت، ڕێک وەک چۆن با ناتوانێت کێوێکی بەردین بهەژێنێت.",
  "9": "هەر کەسێک کە لە گڵاوی و ناپاکی پاک نەبووبێتەوە، و خاوەنی کۆنتڕۆڵی خود و ڕاستگۆیی نەبێت، شایستەی ئەوە نییە جلی زەرد بپۆشێت.",
  "10": "ئەو کەسەی کە لە هەموو ناپاکی و گڵاوییەک پاک بووبێتەوە، لەسەر بنەماکانی ئەخلاق جێگیر بووە، و خاوەنی کۆنتڕۆڵی خود و ڕاستگۆیییە، بێگومان شایستەی پۆشینی جلی زەردە.",
  "11": "ئەوانەی لە شتی لاوەکی و بێبایەخدا، شتی بنەڕەتی و جەوهەری دەبینن، و لە شتی بنەڕەتی و جەوهەریدا، شتی لاوەکی دەبینن؛ ئەو کەسانەی کە خاوەنی ئەم جۆرە بیرکردنەوە چەوتانەن، هەرگیز ناگەنە تێگەیشتن لە جەوهەر و ڕاستی.",
  "12": "ئەوانەی کە شتی بنەڕەتی بە بنەڕەتی دەزانن، و شتی لاوەکی بە لاوەکی دەزانن؛ ئەو کەسانەی کە خاوەنی ئەم جۆرە بیرکردنەوە ڕاست و دروستانەن، دەگەنە تێگەیشتن لە جەوهەر و ڕاستی.",
  "13": "ڕێک وەک چۆن باران دزە دەکاتە ناو خانوویەک کە بەشی سەرەوەی خراپ داپۆشراو بێت، بە هەمان شێوەش ئارەزوو و شەهوەت دزە دەکاتە ناو مێشک و دەروونێکی پێ ڕانەگەیشتوو و ڕانەهێنراوەوە.",
  "14": "ڕێک وەک چۆن باران دزە ناکاتە ناو خانوویەک بەشی سەرەوەی بە باشی داپۆشراو بێت، بە هەمان شێوەش ئارەزوو و شەهوەت دزە ناکاتە ناو مێشک و دەروونێکی تەواو پێگەیشتوو و ڕاهێنراوەوە.",
  "15": "لێرە (لە جیهاندا) خەم دەخوات، لەوێش (دوای مردن) خەم دەخوات. خراپەکار لە هەردوو بارودۆخەکەدا غەمبارە. ئەو خەم دەخوات و دەناڵێنێت، کاتێک درک بە گڵاوی و ناپاکی کارەکانی خۆی دەکات.",
  "16": "لێرە شادی دەکات، لەوێش شادی دەکات. چاکەکار لە هەردوو بارودۆخەکەدا شاد و دڵخۆشە. ئەو کاتێک درک بە پاکی کارەکانی خۆی دەکات، شادی دەکات و بە ڕادەیەکی بێپایان دڵخۆش دەبێت.",
  "17": "لێرە ئازار دەچێژێت، لەوێش ئازار دەچێژێت. خراپەکار لە هەردوو بارودۆخەکەدا دەناڵێنێت. بەم بیرکردنەوەیەی کە دەڵێت 'من خراپەم کردووە' ئازار دەچێژێت. زیاتریش ئازار دەچێژێت کاتێک بەرەو بارودۆخ و چارەنووسێکی پڕ لە ژان و سەرگەردانی بەڕێ دەکەوێت.",
  "18": "لێرە بەختەوەرە، لەوێش بەختەوەرە. چاکەکار لە هەردوو بارودۆخەکەدا بەختەوەرە. بەم بیرکردنەوەیەی کە دەڵێت 'من چاکەم کردووە' بەختەوەرە. زیاتریش بەختەوەر دەبێت کاتێک بەرەو بارودۆخ و چارەنووسێکی پڕ لە ئارامی و فێنکایی ڕۆحی بەڕێ دەکەوێت.",
  "19": "ئەگەرچی ئەو زۆر دەقە پیرۆزەکان دەخوێنێتەوە، بەڵام بەپێی ئەوانە کار ناکات، ئەو مرۆڤە بێئاگایە وەک شوانێک وایە کە مانگاکانی کەسانی تر دەژمێرێت. ئەو هیچ پشکێکی لە بەرهەمەکانی ژیانی پیرۆزدا نییە.",
  "20": "ئەگەر کەسێک دەقە پیرۆزەکان کەمیش بخوێنێتەوە، بەڵام هاوتەریب لەگەڵ فێرکارییەکاندا ڕەفتار بکات، و دەستبەرداری شەهوەت، ڕق و کینە، و نەفامیش بێت، بە جۆرێک کە خاوەن ناسینی ڕاستەقینە و مێشکێکی تەواو ڕزگاربوو بێت، و لێرە و لەوێش وابەستەی هیچ شتێک نەبێت، ئەوا ئەو کەسە بەشدار و هاوبەشە لە بەرهەم و دەستکەوتەکانی ژیانی پیرۆزدا.",
  "chap2": "سەرنجدان",
  "21": "سەرنجدان ڕێگای بەرەو نەمرییە، بێئاگایی ڕێگای بەرەو مردنە. هۆشیاران نامرن؛ بێئاگان وەک مردووانن.",
  "22": "کاتێک مرۆڤە داناکان بە تەواوی لەم جیاوازییە (جیاوازی نێوان وشیاری و بێئاگایی) تێدەگەن، سەرنجی خۆیان دەخەنە سەر وشیاربوون و بەمەش دڵخۆش دەبن، و چێژ لەو ئاستە باڵا ڕۆحییە وەردەگرن کە تایبەتە بە مرۆڤە پاک و پێگەیشتووەکان (ئەریاکان).",
  "23": "ئەوانەی بەردەوام لە ڕاماندان، ئەوانەی هەمیشە جێگیر و بە بڕشتن، بە 'نیبانا'ی باڵا و ڕزگار لە کۆتوبەندەکان دەگەن.",
  "24": "شکۆ و گەورەیی ئەو کەسەی کە پڕ وزە، وشیار، پاک لە کردار، بە سەرنج، خاوەن کۆنتڕۆڵی خود، ڕاستژین و سەرنجدەرە، بە بەردەوامی گەشە دەکات.",
  "25": "بە هەوڵی بەردەوام، دڵسۆزی، دیسپلین و کۆنتڕۆڵی خود، با مرۆڤی دانا دوورگەیەک بۆ خۆی دروست بکات، کە هیچ لافاوێک نوقمی نەکات.",
  "26": "خەڵکی نەفام و گەمژە نوقمی بێئاگایی دەبن؛ بەڵام مرۆڤی دانا وەک گەورەترین گەنجینە پاسەوانی لە دڵسۆزی و وشیاری دەکات.",
  "27": "خۆت ڕادەستی بێئاگایی و غەفڵەت مەکە، و مەبە بە هاودەم و خولیای چێژە کاتییەکانی حەز و ئارەزوو. چونکە بێگومان، ئەو کەسەی وشیارە و بەردەوام لە ناوەخنی خۆیدا ڕادەمێنێت، دەگاتە بەختەوەری و ئاسودەییەکی زۆر گەورە و پایەدار.",
  "28": "کاتێک مرۆڤێکی تێگەیشتوو بەهۆی سەرنجدانەوە بێئاگایی وەلا دەنێت، ئەو کەسە، ئازاد لە خەم، سەردەکەوێت بۆ کۆشکی حیکمەت و لە خەڵکانی خەمبار دەڕوانێت، ڕێک وەک چۆن شاخەوانێکی دانا لە سەرنشینانی نەفامی سەر زەوی دەڕوانێت.",
  "29": "مرۆڤی دانا لە ناو خەڵکانی بێئاگادا هەمیشە وشیارە، و لە ناو ئەوانەی کە نوقمی خەوی غەفڵەت بوون بە ئاگایە. ئەو بەهۆی ئەم کەرامەت و زیرەکییەیەوە بە خێرایی بەرەو پێش دەچێت و پەرە بە ڕۆحی خۆی دەدات، ڕێک وەک چۆن ئەسپێکی بەهێز کاتێک غار دەدات، ئەسپێکی تەمبەڵ و لاواز لە دواوە بەجێدەهێڵێت.",
  "30": "بەهۆی وشیاری و هەوڵی بەردەوامەوە، 'ماگهاڤا' (کە ناوێکی تری تاکی گەورەی خوداکانە لە ئەفسانەی هیندی-بوداییدا) توانی بگاتە بەرزترین پلە و ببێتە پاشای خوداکان. وشیاری و دڵسۆزی هەمیشە لە هەموو شوێنێک شایستەی ستایشە، بەڵام غەفڵەت و کەمتەرخەمی هەمیشە سووک و ڕیسوا دەکرێت.",
  "31": "ئەو 'بهیکخو'یەی (قەشەیەی) کە چێژ لە سەرنجدان وەردەگرێت، و بە ترسەوە لە بێئاگایی دەڕوانێت، وەک ئاگر بەرەو پێش دەچێت، و هەموو کۆت و بەندە گەورە و بچووکەکان دەسووتێنێت.",
  "32": "ئەو 'بهیکخو'یەی کە چێژ لە سەرنجدان وەردەگرێت، و بە ترسەوە لە بێئاگایی دەڕوانێت، ناکەوێت. ئەو لە ئامادەیی 'نیبانا'دایە.",
  "chap3": "ژیری",
  "33": "ژیریی لەرزۆک و سەرکێش، کە پاراستنی قورسە و کۆنتڕۆڵکردنی ئەستەمە؛ مرۆڤی دانا ڕێکی دەخاتەوە، ڕێک وەک چۆن تیرتاشێک تیرێک ڕاست دەکاتەوە.",
  "34": "کاتێک ماسییەک لە ئاو دەردەهێنیت و فڕێی دەدەیتە سەر زەوی وشک، چۆن بۆ مانەوەی پەلەقاژێ دەکات، مێشک و ژیریی مرۆڤیش کاتێک لە شوێنە دەستەمۆ و ئارامەکەی خۆی دوور دەخرێتەوە، بەهۆی هێرشی بەردەوامی حەز و خەیاڵەکانەوە بەو شێوەیە پەلەقاژێ دەکات و تێکدەچێت. لەبەر ئەوە، پێویستە مرۆڤ لە کایەی ئارەزووە نەفسی و شەهوەتییەکان دوور بکەوێتەوە.",
  "35": "ڕاگرتنی ژیری قورسە، خێرایە و بەرەو هەر لایەک کە ئارەزووی بکات باڵ دەگرێت؛ کۆنتڕۆڵکردنی باشە. ژیریی کۆنتڕۆڵکراو بەرەو بەختەوەری دەتبات.",
  "36": "ناسین و دۆزینەوەی مێشک (بزووتنەوەی بیرکردنەوەکان) کارێکی ڕادەبەدەر قورسە، چونکە هۆشیاریی مرۆڤ شتێکی زۆر ناسک، شاراوە و بێشێوەیە؛ ئەو بەبێ ویستی تۆ، چرکە بە چرکە باز دەدات بۆ سەر هەر بابەت یان خەیاڵێک کە ئارەزووی بکات. بۆیە با مرۆڤی دانا بە بەردەوامی چاودێری مێشکی خۆی بکات و بیپارێزێت؛ چونکە مێشکێک کە کۆنتڕۆڵ و پاسەوانی بکرێت، مرۆڤ بەرەو ئارامی و بەختەوەرییەکی ڕاستەقینە ڕێنوێنی دەکات.",
  "37": "دوورەپەرێزە، بە تەنها سەرگەردان دەبێت، بێ جەستەیە و لە ئەشکەوتێکدا پاڵکەوتووە؛ ئەوە ژیرییە. ئەوانەی دەری دەهێنن و دەمکوتی دەکەن، لە کۆتوبەندی 'مارا' (شەیتان/شەڕ) ڕزگاریان دەبێت.",
  "38": "ئەو کەسەی ژیرییەکەی جێگیر نییە، ئەو کەسەی لە بیروباوەڕی ڕاستەقینە تێنەگەیشتووە، ئەو کەسەی متمانەی جێگیر نییە؛ حیکمەتی کەسێکی وەها هەرگیز کامڵ نابێت.",
  "39": "ئەو کەسەی ژیرییەکەی بە شەهوەت نوقم نەبووە، ئەو کەسەی لەژێر کاریگەریی ڕق و کینەدا نییە، ئەو کەسەی لە هەردوو چاکە و خراپە تێپەڕیوە؛ بۆ کەسێکی وەها وشیار هیچ ترسێک نییە.",
  "40": "بە درککردن بەوەی کە ئەم جەستەیە هاوشێوەی گۆزەیەک ناسکە، و بە دامەزراندنی ئەم ژیرییە وەک شارێکی قەڵابەند و بەهێز؛ ئەو دەبێت بە چەکی حیکمەتەوە هێرش بکاتە سەر 'مارا'. ئەو دەبێت دەستکەوتەکانی بپارێزێت و وابەستە نەبێت.",
  "41": "لەم نزیکانەدا، ئەفسوس! ئەم جەستەیە بێ هۆشیاری و فڕێدراو لەسەر زەوی پاڵ دەکەوێت، ڕێک وەک دارێکی سووتاوی بێ سوود.",
  "42": "هەر زیانێک کە دوژمنێک بە دوژمنێکی بگەیەنێت، یان ڕقێک بە ڕق لێبووەیەک، ژیرییەکی سەرلێشێواو و خراپ ئاڕاستەکراو دەتوانێت زیانێکی زۆر گەورەتری پێ بگەیەنێت.",
  "43": "ئەوەی نە دایک، نە باوک، و نە هیچ خزمێکی تر ناتوانن ئەنجامی بدەن؛ ژیرییەکی باش ئاڕاستەکراو ئەنجامی دەدات و بەهۆیەوە مرۆڤ بەرز دەکاتەوە.",
  "chap4": "گوڵەکان",
  "44": "کێ دەتوانێت بە ڕاستگۆیی لە حەقیقەتی ئەم زەوییە، لە کایەی خودای مردن (یاما)، و لە جیهانی پڕ لە چێژی خودا باڵاکان (دێڤاکان) تێبگات؟ کێ دەتوانێت بە قووڵی لەم ڕێگا پاک و ڕاستەقینەیەی ئەخالق بکۆڵێتەوە و پەیڕەوی بکات، ڕێک وەک چۆن تاجەگوڵینەسازێکی شارەزا بە وردی باشترین گوڵەکان لە نێو باخچەدا هەڵدەبژێرێت؟",
  "45": "ئەو فێرخوازەی کە بە ڕاستگۆییەوە لەسەر ڕێگای ڕاهێنانی ڕۆحی و هۆشیاری دایە، دەتوانێت بە تەواوی لەم زەوییە، لە حەقیقەتی مردن و تەنانەت لە جیهانی خودا باڵاکانیش (دێڤاکان) تێبگات. ئەم فێرخوازە لێهاتووە، بە قووڵی لەو ڕێگا ئەخالقی و پاکە دەکۆڵێتەوە کە بودا فێری کردووە، ڕێک وەک چۆن تاجەگوڵینەسازێکی شارەزا بە وردی و جوانی بەنێو باخچەدا دەگەڕێت و باشترین گوڵەکان بۆ کارەکەی هەڵدەبژێرێت.",
  "46": "کاتێک مرۆڤ دەزانێت و تێدەگات کە ئەم جەستە مادییە وەک کەفی سەر ئاو ناسک و کاتییە، و درک بەوە دەکات کە تەواوی ژیانی دنیا سروشتێکی سەرابئامێزی هەیە (واتە تەنها خەیاڵ و دیمەنێکی تێپەڕە)، ئەو کاتە دەتوانێت تیرە گوڵینەکانی ئارەزوو و شەهوەتە نەفسییەکان (کە تەڵە و نێچیرەکانی 'مارا' یان شەیتانن) تێکبشکێنێت، و بە تەواوی لە بازنەی دەسەڵات و بەرچاوی پاشای مردن ون بێت و تێپەڕێت.",
  "47": "ئەو مرۆڤەی کە بەردەوام خەریکی کۆکردنەوەی گوڵەکانە (واتە تەنها ڕاوچیی چێژە کاتی و مادییەکانی ژیانە) و مێشکی بە تەواوی باڵو، لێڵ و سەرگەردان بووە لە نێو حەزەکانیدا؛ مردن بە کتوپڕی دێت و ڕایدمالێت و لەناوی دەبات، ڕێک وەک چۆن لافاوێکی خێرا و بێبەزەیی شەوانە هەڵدەقۆڵێت و لادێیەکی خەوتوو بە تەواوی لەگەڵ خۆیدا دەبات.",
  "48": "ئەو مرۆڤەی کە گوڵەکان (چێژە کاتییەکانی حەز) کۆدەکاتەوە، و مێشکی باڵوە، و هەرگیز لە ئارەزووەکانی تێر نابێت؛ 'تێکدەر' (مردن) دەیخاتە ژێر ڕکێف و دەسەڵاتی خۆیەوە.",
  "49": "وەک چۆن مێشهەنگێک بەبێ ئەوەی زیان بە گوڵەکە، بە ڕەنگەکەی یان بە بۆنەکەی بگەیەنێت، تەنها هەنگوینەکە کۆدەکاتەوە و دەفڕێت؛ دانا و پیریش دەبێت بەو شێوەیە لە نێو لادێ و خەڵکدا بسوڕێتەوە (بەبێ تێکدانی دەوروبەر).",
  "50": "با کەس بەدوای کەم و کوڕی و هەڵەی کەسانی تردا نەگەڕێت، نە بەدوای ئەو کارانەی کە خەڵکی کردوویانە یان فەرامۆشیان کردووە؛ بەڵکو تەنها با بەدوای کارەکانی خۆیدا بگەڕێت، ئەو کارانەی کە کردوویەتی یان جێی هێشتوون.",
  "51": "وەک چۆن گوڵێک هەیە کە زۆر نازدار، ڕەنگاوڕەنگ و جوانە بەڵام هیچ بۆن و بەرامەیەکی خۆشی نییە؛ ڕێک بەو شێوەیەش، ئەو قسە جوان، حەکیمانە و دروستانەی کە مرۆڤەکە دەیانڵێت بەڵام خۆی پەیڕەوییان ناکات و کاریان پێناکات، بێبڕشت، بێسوود و بێبەرھەمن.",
  "52": "وەک گوڵێک کە نازدار، جوان و پڕ لە بۆنی خۆشە، ڕێک بەو شێوەیەش بەپیت و بەبڕشتە ئەو قسە جوان و دروستەی کە مرۆڤەکە خۆی پەیڕەوی دەکات و کاری پێدەکات.",
  "53": "وەک چۆن لە کۆمەڵێک گوڵی زۆرەوە چەندین تاجەگوڵینە دروست دەکرێت، بە هەمان شێوەش دەبێت لەلایەن مرۆڤێکی فانییەوە (کە لەدایکبووی جیهانی مردنە) چەندین کاری چاک و ئەخالقی ئەنجام بدرێت.",
  "54": "بۆنی خۆشی گوڵەکان بە پێچەوانەی ئاڕاستەی باوە نایەت، نە بۆنی داری سەندەل، نە بۆنی 'تاگارا' (گوڵێکی بۆنخۆشی هیندی) و نە یاسەمین؛ بەڵکو بۆنی خۆشی مرۆڤی خاوەن ئەخالق و پاک بە پێچەوانەی ئاڕاستەی باوە دێت؛ مرۆڤی خاوەن ئەخالق بە هەموو لایەکدا باڵو دەبێتەوە.",
  "55": "داری سەندەل، تاگارا، نیلوفەر، یاسەمین: لە سەرووی هەموو ئەم جۆرە بۆنە خۆشانەوە، بۆنی ئەخالق و پاکی، بە ڕادەیەکی زۆر باڵاتر و باشترە.",
  "56": "بۆنی تاگارا یان سەندەل بایەخێکی کەم و بچووکی هەیە؛ بەڵام بۆنی خۆشی مرۆڤی خاوەن ئەخالق، کە تەنانەت لە نێوان خوداکانیشدا باڵو دەبێتەوە، باڵاترین و بێوێنەیە.",
  "57": "'مارا' (شەیتان/شەڕ) ناتوانێت ڕێگای ئەو کەسانە بدۆزێتەوە کە خاوەن ئەخالقن، لە ژیانیاندا وشیار و بەدیقەتن، و بەهۆی ناسینی ڕاستەقینەوە ئازاد و ڕزگار بوون.",
  "58": "وەک چۆن لەسەر کۆمەڵە خاشاک و پاشماوەیەک کە فڕێدراوەتە سەر شاڕێگاکان، لەوانەیە گوڵە نیلوفەرێکی نازدار و بۆنخۆش شین بێت و گەشە بکات؛",
  "59": "ڕێک بەو شێوەیەش لە نێوان بوونەوەرە بێبایەخ و تاریکەکاندا، فێرخوازێک 'ئەو کەسەی کە بە تەواوی ڕووناک بووەتەوە' (بودا)، بەهۆی حیکمەتەکەیەوە بەسەر خەڵکانی نابینای جیهاندا دەدرەوشێتەوە.",
  "chap5": "نەزانەکان (کەمئەقڵەکان)",
  "60": "شەو درێژە بۆ ئەو کەسەی بەئاگایە و خەوی لێناکەوێت؛ ڕێگا درێژە بۆ ڕێبوارێکی ماندوو؛ بە هەمان شێوەش، سوڕی لەدایکبوونەوەی بەردەوام (سامسارا) ڕادەبەدەر درێژ و بێبڕانەوەیە بۆ کەسانی نەزان کە لە حەقیقەتی باڵا و پیرۆز تێنەگەیشتوون.",
  "61": "ئەگەر مرۆڤێک لە کاتی بڕینی ڕێگای گەشەی دەروونی و هۆشیاربوونەوەیدا، نەیتوانی هاوڕێ، هاوسەفەر یان مامۆستایەک بدۆزێتەوە کە لە خۆی تێگەیشتووتر بێت، یان لانیکەم لە ڕووی فیکری و ئەخالقییەوە هاوشانی خۆی بێت؛ ئەوا با بە تەواوی پشت بە خۆی ببەستێت و بە تەنها بەردەوام بێت لەسەر ڕێگاکەی. چونکە مانەوە لەناو تەنهاییدا بێبایەخ نییە، بەڵام هاوڕێیەتی و تێکەڵاوبوون لەگەڵ کەسانی نەزان و بێئاگا، هیچ جۆرە گەشە و بەرهەمێکی تێدا نییە.",
  "62": "مرۆڤی نەزان و بێئاگا بەردەوام خۆی بەم بیرکردنەوانەوە سەرقاڵ دەکات و تووشی دڵەڕاوکێ دەبێت: 'من منداڵم هەیە کە پشت و پەنام بن، من سەروەت و سامانی زۆرم هەیە کە ببنە مایەی دڵنیاییم'. بەڵام ئەو لە ڕاستییە قووڵەکە تێناگات؛ ئەو تەنانەت خاوەنی خودی خۆی، جەستەی خۆی و مێشکی خۆی نییە (چونکە هەموویان کاتی و فانین و کۆنتڕۆڵی تەواویان بەسەردا نییە)، ئیتر چۆن دەکرێت منداڵ و سەروەت بە ڕاستی هی ئەو بن و پشکی هەمیشەیی ئەو بن؟",
  "63": "ئەو نەزانەی کە دەزانێت نەزانە، ڕێک بەهۆی ئەم وشیارییەوە دەکرێت بە مرۆڤێکی دانا ئەژمار بکرێت؛ بەڵام ئەو نەزانەی پێی وایە زانا و دانایە، لە ڕاستیدا ئەو نەزانێکی تەواوە.",
  "64": "ئەگەر نەزانێک لە درێژایی تەواوی ژیانیدا هاوڕێیەتی مرۆڤێکی دانا بکات، هێشتا لە 'داما' (حەقیقەت و یاسای گەردوونی) تێناگات؛ ڕێک وەک چۆن کەوچکێک تامی شۆربا ناکات و پێی نازانێت.",
  "65": "بەڵام کەسێکی وشیار و تێگەیشتوو، ئەگەر تەنها بۆ چرکەیەکیش هاوڕێیەتی مرۆڤێکی دانا بکات، زۆر خێرا لە 'داما' تێدەگات؛ ڕێک وەک چۆن زمان بە خێرایی تامی شۆربا دەچێژێت.",
  "66": "نەزانانی کەمئەقڵ بە شێوەیەک بە جیهاندا دەسووڕێنەوە کە خودی خۆیان کردووە بە دوژمنی خۆیان؛ ئەوان کارگەلی خراپ ئەنجام دەدەن کە بەرهەم و ئاکامەکەی تفت و تاڵە.",
  "67": "ئەو کارە بە چاکە ئەژمار ناکرێت کە مرۆڤ دوای ئەنجامدانی پەشیمان ببێتەوە، و بە چاوی پڕ لە فرمێسک و گریانەوە بەرهەمی تاڵی ئەو کارەی بچنێتەوە.",
  "68": "بەڵکو ئەو کارە بە چاکە ئەژمار دەکرێت کە مرۆڤ دوای ئەنجامدانی پەشیمان نەبێتەوە، و بە شادی، کەیفخۆشی و ئارامییەوە بەرهەمە شیرینەکەی بچنێتەوە.",
  "69": "کارێکی خراپ لە دیدی نەزانەوە وەک هەنگوین شیرینە، تا ئەو کاتەی کە بەرهەمەکەی پێدەگات؛ بەڵام کاتێک کارماکەی گەیشت و بەرهەمی هێنا، ئەو کاتە نوقمی ژان و خەمۆکی دەبێت.",
  "70": "مرۆڤی نەزان و ڕواڵەتپەرست لەوانەیە مانگ دوای مانگ (بۆ خۆدەرخستن و نیشاندانی ئەوەی کە زاهید و دیندارە) خۆی برسی بکات و تەنها هێندەی نووکی گەڵایەکی تیژ (وەک سەرە دەرزییەک) نان بخوات؛ بەڵام ئەم ڕاهێنانە سەخت و ڕووکەشییەی ئەو، هێندەی بەشی شازدەیەمینی (واتە کەمترین بەشی) بەهای ئەو ڕێبوارە وشیارە نییە کە تەنها یەکجار حەقیقەتی باڵای ناسیوە و لێی تێگەیشتووە.",
  "71": "لە ڕاستیدا، کاتێک مرۆڤ کارێکی خراپ و نادروست ئەنجام دەدات، بەرهەمە تاڵ و سزاکەی دەستبەجێ دەرناکەوێت، ڕێک وەک چۆن شیری تازە دۆشراو یەکسەر نابێتە ماست (بەڵکو کاتی دەوێت)؛ بەڵام ئەو کارە خراپە وەک پشکۆیەکی سووتێنەر کە لەژێر خۆڵەمێشدا شاردراوەتەوە، بە بێدەنگی و هێواشی بەدوای مرۆڤە نەزانەکەدا دەچێت و لە کاتی گونجاودا دەست دەکات بە سووتاندنی ژیانی.",
  "72": "بۆ ماڵوێرانی و لەناوچوونی خۆیەتی کە نەزان دەست دەداتە کۆکردنەوەی زانیاریی ڕووکەش و ناوبانگ؛ چونکە ئەم دەستکەوتانە بەختیارییە ڕووناکەکەی تێکدەشکێنن و مێشکی تێکدەدەن.",
  "73": "مرۆڤی نەزان خولیای ناوبانگێکی درۆینەیە؛ ئەو دەیەوێت لە پەرستگەدا لە پێشەوەی هەموو ڕێبوار و نیشتەجێبووان بێت (پێشەنگ بێت)، دەسەڵاتی ڕەها و کۆنتڕۆڵی بەسەر خانەقا و پەرستگەکاندا هەبێت، و لە لایەن خێزان و بنەماڵەکانی تریشەوە هەمیشە ڕێزی لێ بگیرێت و ستایش بکرێت.",
  "74": "ئەو حەز دەکات هەموو خەڵکی ئاسایی و هەموو ڕێبوارانی پەرستگە ئاوا بیربکەنەوە: 'ئەم کارە تەنها بە دەستی من ئەنجام دراوە؛ لە هەر کارێکی گەورە یان بچووکدا، دەبێت بگەڕێنەوە بۆ لای من'. ئەمە تەماح و خولیای نەزانە؛ بەمەش هەمیشە ئارەزووە نەفسییەکان و لوتبەرزییەکەی ڕوو لە زیادبوون دەکەن.",
  "75": "بە دڵنیاییەوە ئەو ڕێگایەی بەرەو دەستکەوتی مادیی جیهان دەچێت جیاوازە، و ئەو ڕێگایەی بەرەو 'نیبانا' (ڕزگاریی ڕەها) دەچێت جیاوازە؛ بە تێگەیشتن لەم جیاوازییە، 'بیکو' (ڕێبواری بودایی، فێرخوازی بودا) نابێت بە سەرنجی مادی و دڵسۆزیی خەڵکی دنیا دڵخۆش بێت، بەڵکو دەبێت پەرە بە گۆشەگیری و دابڕانی دەروونی (نەوابەستەیی) بدات.",
  "chap6": "داناکان",
  "76": "ئەگەر مرۆڤ کەسێکی دانای بینی کە وەک نیشاندەری گەنجینەیەک، کەموکوڕییەکان دەستنیشان دەکات و لۆمە دەکات؛ با تێکەڵی لەگەڵ وەها کەسێکی دانادا بکات؛ بۆ ئەو کەسەی تێکەڵی لەگەڵ دەکات باشتر دەبێت، نەک خراپتر.",
  "77": "با ئامۆژگاری بکات، ڕێنمایی بکات، و مرۆڤ لە خراپە دوور بخاتەوە؛ بە ڕاستی ئەو لای چاکەکاران پەسەندە، و لای خراپەکاران ناپەسەندە.",
  "78": "تێکەڵی لەگەڵ هاوڕێی خراپدا مەکە، تێکەڵی لەگەڵ مرۆڤی نزم و ڕەزیلدا مەکە؛ تێکەڵی لەگەڵ هاوڕێی چاکدا بکە، تێکەڵی لەگەڵ مرۆڤی بەڕێز و جوامێردا بکە.",
  "79": "ئەوەی (پەیامی) 'داما' وەردەگرێت، بە مێشکێکی ئارامەوە لە بەختەوەریدا دەژی؛ مرۆڤی دانا هەمیشە دڵی بەو 'داما'یە خۆشە کە لە لایەن 'ئاریاکان'ەوە ئاشکرا کراوە.",
  "80": "ئاودێران ئاوەکە ئاڕاستە دەکەن؛ تیرسازان تیرەکان دەچەمێننەوە؛ دارتاشان دارەکان دەچەمێننەوە؛ داناکانیش کۆنتڕۆڵی خۆیان دەکەن.",
  "81": "وەک چۆن تاشەبەردێکی ڕەق بە با ناجوڵێت، بە هەمان شێوە داناکانیش بە ستایش یان لۆمەکردن ناهەژێن.",
  "82": "ڕێک وەک چۆن دەریاچەیەکی قووڵ، ڕوون و بێدەنگە، بە هەمان شێوەش، داناکان بە بیستنی فێرکارییەکان، بە ڕادەیەکی زۆر ئاشتی و ئارامی بەدەست دەهێنن.",
  "83": "چاکەکاران دەست لە پەیوەستبوون بە هەموو شتێک هەڵدەگرن؛ پیاوچاکان بە ئارەزووی شەهوانییەوە چەلەحانێ ناکەن: جا چ بکەونە ژێر کاریگەری بەختەوەری یان ئازار، داناکان نە دڵخۆشییەکی لەڕادەبەدەر و نە دڵتەنگی نیشان دەدەن.",
  "84": "نە لەبەر خاتری خۆی و نە لەبەر خاتری کەسێکی تر (مرۆڤی دانا چەوتی ناکات)؛ نابێت بە کارێکی چەوت ئارەزووی کوڕ، سامان یان پادشایەتی بکات: نابێت بە ڕێگەی نادادپەروەرانە داوای سەرکەوتوویی خۆی بکات. تەنها لەو کاتەدا وەها کەسێک بە ڕاستی خاوەن ڕەوشت، دانا و دادپەروەرە.",
  "85": "کەم هەن لەنێو مرۆڤەکاندا کە بڕۆن بۆ ئەوسەر (ئەوبەری ڕووبارەکە)؛ ئەوانی تری مرۆڤایەتی تەنها لەسەر کەنارەکە دەبەزن و دێن و دەچن.",
  "86": "بەڵام ئەوانەی بە دروستی بەپێی فێرکارییەکە ڕەفتار دەکەن، کە بە باشی ڕوون کراوەتەوە، ئەوانە ئەو کەسانەن کە دەگەنە ئەوسەر (نیبانا) بە پەڕینەوە لە کایەی ئارەزووەکان کە پەڕینەوە لێی زۆر سەختە.",
  "87": "مرۆڤی دانا کاتێک لە ژیانی ناو ماڵەوە کۆچ دەکات بۆ ژیانی بێماڵی (تەرککردنی ژیانی دنیایی و ڕووکردنە ڕەبەنایەتی)، دەبێت واز لە ڕێگا و دۆخە تاریکەکان بهێنێت و گەشە بە دۆخە ڕووناک و پاکەکان بدات.",
  "88": "دەبێت لەو گۆشەگیری و دابڕانەدا (نیبانا) داوای قووڵترین چێژ و دڵخۆشی بکات، کە چێژوەرگرتن لێی (بۆ خەڵکی ئاسایی) زۆر سەختە. مرۆڤی دانا بە دەستبەرداربوون لە خۆشییە شەهوانییەکان و بە بێ هەبوونی هیچ کۆسپ و تەگەرەیەک لە دەروونیدا، دەبێت خۆی لە هەموو پیسی و خەوشەکانی مێشک پاک بکاتەوە.",
  "89": "ئەوانەی مێشکیان بە تەواوی ڕاهێنراوە لە 'فاکتەرەکانی ڕۆشنابوونەوە'دا، ئەوانەی بێ ئەوەی دەست بە شتەوە بگرن، دڵیان بە 'دەستبەرداربوون لە چنگەکوتێ' (واتە: نیبانا) خۆشە، ئەوان، کەسە درەوشاوە و ناگەندەڵکارەکانن، تەنانەت لەم جیهانەشدا گەیشتوونەتە نیبانا.",
  "chap7": "ئەرەهانتەکان- شایستەکان",
  "90": "بۆ ئەو کەسەی کە گەشتەکەی کۆتایی پێ هێناوە، بۆ ئەو کەسەی کە بێ خەم و پەژارەیە، بۆ ئەو کەسەی کە لە هەموو شتێک بە تەواوی ئازاد بووە، بۆ ئەو کەسەی کە هەموو کۆت و بەندەکانی پساندووە، تاوی (ئارەزووی شەهوانی) بوونی نییە.",
  "91": "مرۆڤە هۆشیار و بەئاگاکان هەمیشە لە کۆشش و بەخۆداچوونەوەدان. ئەوان بە هیچ شوێن و جێگایەکی ئەم دنیایەوە دڵبستە و پێوەست نابن. ڕێک وەک ئەو قازە کێوییانەی کە گۆمەکانی خۆیان بەجێ دەهێڵن و دەفڕن، ئەوانیش بەبێ بەستراوەیی، ماڵ بە ماڵ و قۆناغ بە قۆناغی ژیان تێ دەپەڕن و ڕوو دەکەنە ئازادیی ڕەها.",
  "92": "ئەوانەی کە هیچ سامان و شتێک بۆ مەیلی دنیایی پاشەکەوت ناکەن، و بە هۆشیارییەوە لە ڕاستیی خۆراکیان ڕادەمێنن (تەنها بۆ مانەوەی جەستە دەیخۆن نەک بۆ چێژ)، ئامانجی سەرەکییان گەیشتنە بەو ڕزگارییەی کە پۆشراوە بە 'پووچەڵی' (خاڵیبوون لە تەماح و خودپەرستی) و 'بێ نیشانەیی' (ئازادبوون لە خەوش و وێنای کاتی)؛ ڕێڕەوی ژیانی ئەوان هێندە بێگەرد و بێ شوێنەوارە، کە وەک فڕینی باڵندەکان لە ئاسماندا، ناتوانرێت شوێنپێی هەڵ بگیرێت یان کۆت و بەند بکرێت.",
  "93": "ئەو کەسەی کە خەوش و گەندەڵییەکانی دەروونی لەناوچوون، ئەو کەسەی کە سەرگەرمی خۆراک نییە، ئەو کەسەی کە ڕزگاربوونی پووچەڵ و بێ نیشانە ئامانجیانە، ڕێگای ئەو، وەک ڕێگای باڵندەکان لە ئاسماندا، شوێنپێی هەڵناگیرێت.",
  "94": "ئەو کەسەی کە هەستەکانی ڕامکراون، وەک ئەو ئەسپە توندوتیژانەی کە لە لایەن گالیسکەوانێکەوە بە باشی ڕاهێنراون، ئەو کەسەی کە شانازی و لووتبەرزییەکەی لەناوچووە و لە خەوشەکان ئازاد بووەتەنانەت خوداوەندەکانیش وەها کەسێکی خۆڕاگر و جێگیریان خۆش دەوێت.",
  "95": "مرۆڤی هاوسەنگ و بە دیسپلین، وەک زەوی، کینە و دژایەتی پیشان نادات. ئەو بەراورد دەکرێت بە 'ئینداخیال' (کۆڵەکەی بەردینی جێگیری دەروازەی شار). ئەو وەک گۆمێکی بێگەرد و پاکە کە بە قوڕ نەشێواوە؛ بۆ وەها کەسێکی هاوسەنگ، سەرگەردانییەکانی ژیان (خولی لەدایکبوونەوە) چیتر سەرهەڵنادەنەوە.",
  "96": "ئارامە مێشکی، ئارامە وتاری، ئارامە ڕەفتاری؛ ئەو کەسەی بە زانینی دروستەوە، بە تەواوی ئازاد بووە، بە تەواوی ئاشتیخواز و هاوسەنگ بووە.",
  "97": "ئەو مرۆڤەی کە ساویلکە (خۆشباوەڕ) نییە، ئەوەی لە 'نەکراو/نەئافێنراو' (نیبانا) تێ دەگات، ئەوەی پەیوەندی و بەستەرەکانی پچڕاندووە، ئەوەی کۆتایی بە هۆکارەکانی (چاکە و خراپە) هێناوە، ئەوەی وازی لە هەموو ئارەزووەکان هێناوە، ئەو بە ڕاستی مرۆڤێکی باڵایە.",
  "98": "جا لە گوند بێت یان لە دارستان، لە دۆڵ بێت یان لەسەر گرد، لە هەر شوێنێک کە 'ئەرەهانتەکان' (پیاوچاکە بەدیهاتووەکان) تێیدا بژین، بە ڕاستی ئەو شوێنە دڵگیر و خۆشە.",
  "99": "ئەو دارستانە چۆڵ و کەنارانەی کە خەڵکی ئاسایی و دنیایی چێژیان لێ نابینن و تێیدا بێزار دەبن، لە ڕاستیدا شوێنی زۆر دڵگیر و ئارامن؛ چونکە ئەو کەسانەی لە ئارەزووی دەروونی و شەهوانی ئازاد بوون، لەو شوێنە بێدەنگانەدا شادمان و دڵخۆش دەبن، لەبەر ئەوەی ئەوان چیتر بەدوای چێژە کاتییەکانی ماددە و جەستەدا ناگەڕێن.",
  "chap8": "هەزارەکان",
  "100": "چاکترە لە هەزار وتار کە لە وشەی بێسوود پێکهاتوون، تەنها یەک وشەی بەسوود کە مرۆڤ بە بیستنی ئارام دەبێتەوە.",
  "101": "چاکترە لە هەزار دێڕە شیعر کە لە وشەی بێسوود پێکهاتوون، تەنها یەک دێڕی بەسوود کە مرۆڤ بە بیستنی ئارام دەبێتەوە.",
  "102": "ئەگەر مرۆڤێک تەنانەت سەد دێڕە شێعر یان پەخشانی ئایینی بە دەنگی بەرز بخوێنێتەوە کە لە وشەی بێسوود و بێهودە پێکهاتوون، تەنها بیستنی یەک وشە یان یەک ڕستە لە پەیامی ڕاستەقینەی فێرکارییەکان (داما) چاکترە، چونکە ئەو تاقە وشەیە دەبێتە هۆی هێنانەدی ئارامی و دڵنیایی لە دەروونیدا.",
  "103": "ئەگەر مرۆڤێک لە گۆڕەپانی جەنگدا بتوانێت ڕووبەڕووی سوپایەکی مەزن ببێتەوە و ملیۆنێک جەنگاوەر ببەزێنێت، سەرکەوتنەکەی تەنها دەرەکی و کاتییە؛ بەڵام ئەو کەسەی کە دەتوانێت بەسەر نەفس، حەزەکان و دەروونی خۆیدا سەرکەوێت و کۆنتڕۆڵیان بکات، بە ڕاستی مەزنترین و بەڕێزترین سەرکەوتووی سەر زەوییە.",
  "104": "سەرکەوتن بەسەر خوددا، بە ڕاستی زۆر مەزنترە لە سەرکەوتن بەسەر تەواوی خەڵکانی تردا؛ نە خوداوەندێک، نە 'گاندهەبایەک' (مۆسیقاژەنە ئاسمانییەکان)، نە 'مارا' (شەیتان/شەهوەت) لەگەڵ 'برەهما'دا، ناتوانن ئەو سەرکەوتنە لە چۆک دابنێن",
  "105": "یان بیبەنەوە لە کەسێک کە خۆی ڕامکردووە و هەمیشە لەژێر کۆنترۆڵدا دەژی.",
  "106": "ئەگەر مرۆڤێک مانگ لە دوای مانگ، بە بەهای هەزار (پاتە یان دراو)، بۆ ماوەی سەد ساڵ قوربانی پێشکەش بکات، بەڵام تەنها بۆ چرکەیەک، ڕێز لە پیاوچاکێک بگرێت کە خۆی گەیاندووەتە باڵایی، ئەو ڕێزگرتنە، بە ڕاستی چاکترە لە سەدەیەک قوربانیکردن.",
  "107": "ئەگەر مرۆڤێک بۆ ماوەی سەد ساڵ خزمەتی ئاگری پیرۆز لە دارستاندا بکات، بەڵام تەنها بۆ چرکەیەک، ڕێز لە پیاوچاکێک بگرێت کە خۆی گەیاندووەتە باڵایی، ئەو ڕێزگرتنە، بە ڕاستی چاکترە لە سەدەیەک قوربانیکردن بۆ ئاگر.",
  "108": "لەم جیهانەدا، هەر خێر یان بەخشینێک کە کەسێکی خێرخواز بۆ ماوەی ساڵێک پێشکەشی بکات، هەموو ئەوە هێندەی چارەکێکی ئەو ڕێز و نەوازشە نییە کە نیشانی کەسانی سەرڕاست و باڵا دەدرێت.",
  "109": "بۆ ئەو کەسەی کە ڕاهاتووە هەمیشە ڕێز و حورمەت لە کەسانی بەتەمەن، دانا و خاوەن ئەزموون بگرێت، چوار چاکە و بەرەکەت لە ژیانیدا گەشە دەکەن و زیاد دەکەن، کە ئەوانیش: درێژیی تەمەن، جوانی و سەرنجڕاکێشیی ڕوخسار و دەروون، بەختەوەری و شادومانی، لەگەڵ هێز و توانای جەستەیی و ڕۆحی.",
  "110": "ئەگەر مرۆڤێک بۆ ماوەی سەد ساڵیش بژی، بەڵام ژیانێکی بێڕەوشت، بەڕەڵا و بێکۆنترۆڵی هەبێت، تەنها یەک ڕۆژ ژیان لە لایەن کەسێکەوە کە خاوەن بنەمای ڕەوشتی بێت و کاتەکانی بە قووڵبوونەوە و مێدیتەیشن (بۆ گەیشتن بە هۆشیاری) بەسەر ببات، زۆر چاکتر و بەهاداترە.",
  "111": "ئەگەر مرۆڤێک بۆ ماوەی سەد ساڵیش تەمەن بکات، بەڵام ژیانێکی بێدانایی، بێعەقڵانی و بێئاگایی هەبێت و هیچ کۆنترۆڵێکی بەسەر مێشک و حەزەکانیدا نەبێت، تەنها یەک ڕۆژ ژیان لە لایەن کەسێکەوە کە دانا و هۆشیار بێت و کاتەکانی بە قووڵبوونەوەی دەروونی و مێدیتەیشن بەسەر ببات، زۆر چاکتر و بەهاداترە.",
  "112": "ئەگەر مرۆڤێک بۆ ماوەی سەد ساڵیش تەمەن بکات، بەڵام ژیانێکی تەمەڵ، بێکارە و سست بەسەر ببات کە هیچ جووڵە و بەرهەمێکی تێدا نەبێت، تەنها یەک ڕۆژ ژیان لە لایەن کەسێکەوە کە هەوڵێکی توند و چڕ دەدات و کۆششی دەروونی دەکات (بۆ گەیشتن بە هۆشیاری و ڕزگاری)، زۆر چاکتر و بەهاداترە.",
  "113": "ئەگەر مرۆڤێک سەد ساڵ بژی بێ ئەوەی تێبگات چۆن هەموو شتەکان سەرهەڵدەدەن و لەناو دەچن، هێشتا بە ڕاستی یەک ڕۆژ ژیانی کەسێک کە تێدەگات چۆن هەموو شتەکان سەرهەڵدەدەن و لەناو دەچن، چاکترە.",
  "114": "ئەگەر مرۆڤێک سەد ساڵ بژی بێ ئەوەی دۆخی نەمر (مردن نەبوو / نیبانا) ببینێت، هێشتا بە ڕاستی یەک ڕۆژ ژیانی کەسێک کە دۆخی نەمر دەبینێت، چاکترە.",
  "115": "ئەگەر مرۆڤێک سەد ساڵ بژی بێ ئەوەی حەقیقەتی باڵا ببینێت، هێشتا بە ڕاستی یەک ڕۆژ ژیانی کەسێک کە حەقیقەتی باڵا دەبینێت، چاکترە.",
  "chap9": "خراپەکاری",
  "116": "پەلە بکە لە ئەنجامدانی کاری چاکە؛ مێشکت لە خراپەکاری بپارێزە؛ چونکە مێشکی ئەو کەسەی کە خاو و سستە لە ئەنجامدانی کاری چاکە، مەیلی بەرەو خراپەکاری دەچێت و چێژی لێ دەبینێت.",
  "117": "ئەگەر مرۆڤێک تووشی کارێکی خراپ بوو، نابێت دووبارە و دووبارە بیکاتەوە؛ نابێت چێژ لەو کارەدا بدۆزێتەوە؛ چونکە کۆبوونەوە و کەڵەکەبوونی خراپە پڕ لە ئازارە.",
  "118": "ئەگەر مرۆڤێک کارێکی چاک و بەهاداری ئەنجام دا، با دووبارە و دووبارە بیکاتەوە؛ با چێژ لەو کارەدا بدۆزێتەوە؛ چونکە کۆبوونەوە و کەڵەکەبوونی چاکە پڕ لە بەختەوەرییە.",
  "119": "تەنها ئەو کەسەی کاری خراپیش دەکات، ڕەنگە بۆ ماوەیەک لە خۆشی و ئاسوودەییدا بژی و وەک کەسێکی سەرکەوتوو دەربکەوێت، تا ئەو کاتەی دەرئەنجامی کردەوە خراپەکەی دەگاتە قۆناغی تێپەڕبوون و دەرکەوتن؛ بەڵام کاتێک کاتی خۆی دێت و کارەکەی بەرهەم دەگرێت، ئەوا ڕووبەڕووی سەرجەم دەرئەنجامە تاڵ و سزاکانی کردەوەکانی خۆی دەبێتەوە.",
  "120": "تەنها ئەو کەسەی کاری چاک و دروستیش دەکات، ڕەنگە بۆ ماوەیەک لە ناخۆشی، ڕەنج یان سەختیدا بژی و وەک کەسێکی بێبەش دەربکەوێت، تا ئەو کاتەی دەرئەنجامی کردەوە چاکەکەی دەگاتە قۆناغی پێگەیشتن و دەرکەوتن؛ بەڵام کاتێک کاتی خۆی دێت و کارەکەی بەرهەم دەگرێت، ئەوا ڕووبەڕووی سەرجەم دەرئەنجامە باش، ئارامبەخش و پڕ لە بەختەوەرییەکانی کردەوەکانی خۆی دەبێتەوە.",
  "121": "بە کەم سەیری خراپە مەکە و مەڵێ: 'ئەمە لە من نزیک نابێتەوە'؛ تەنانەت گۆزەیەکی ئاویش بە دڵۆپە دڵۆپ باران پڕ دەبێت؛ بە هەمان شێوە، مرۆڤی نەزان کاتێک کەم کەم خراپە کۆدەکاتەوە، خۆی پڕ دەکات لە خراپەکاری.",
  "122": "بە کەم سەیری چاکە مەکە و مەڵێ: 'ئەمە لە من نزیک نابێتەوە'؛ تەنانەت گۆزەیەکی ئاویش بە دڵۆپە دڵۆپ باران پڕ دەبێت؛ بە هەمان شێوە، مرۆڤی دانا کاتێک کەم کەم چاکە کۆدەکاتەوە، خۆی لە چاکە پڕ دەکات.",
  "123": "ڕێک وەک چۆن بازرگانێک کە کاروانێکی بچووک و سامانێکی زۆری پێیە، بە هۆشیارییەوە لە ڕێگایەکی پڕ لە چەتە و مەترسی دوور دەکەوێتەوە بۆ ئەوەی سامانەکەی نەفەوتێت، و وەک چۆن کەسێک کە دەیەوێت بە ساغی بژی، بە تەواوی لە ژەهر دوور دەکەوێتەوە؛ بە هەمان شێوەش، مرۆڤ دەبێت بە ئاگایی و وریاییەکی تەواوەوە لە هەموو جۆرە کار و بیرکردنەوەیەکی خراپ دوور بکەوێتەوە، چونکە زیان بە جەوهەر و هۆشیاریی دەگەیەنن.",
  "124": "ئەگەر لە دەستی مرۆڤدا هیچ برین، قڵیش یان پێستلێبوونەوەیەک نەبێت، دەتوانێت ژەهر بە دەستیەوە بگرێت بەبێ ئەوەی زیانی پێ بگات، چونکە ژەهرەکە ناتوانێت بچێتە ناو جەستەیەوە؛ بە هەمان شێوە، ئەگەر دەروون و هۆشیاریی مرۆڤ پاک بێت و هیچ مەیلی لاری یان مەبەستێکی خراپی تێدا نەبێت، دەرئەنجامە خراپ و ناخۆشەکانی جیهانی دەرەوە کاریگەریی تێ ناکەن، چونکە لە بنەڕەتدا چەوتی و خراپە لە ناخی ئەودا بوونی نییە تا زیانی پێ بگەیەنێت.",
  "125": "هەر کەسێک ئازاری کەسێکی بێزیان، بێگەرد و بێتاوان بدات، خراپەکەی بەسەر خودی ئەو مرۆڤە نەزانەدا دەگەڕێتەوە، ڕێک وەک ئەو تۆزە وردەی کە بە ڕووی بادا هەڵدەدرێت (و دەگەڕێتەوە بۆ ناو چاوی فڕێدەرەکە).",
  "126": "مرۆڤەکان دوای مردن بەپێی ئاستی هۆشیاری و کردەوەکانیشان دابەش دەبن: هەندێکیان کە هێشتا بەستراونەتەوە بە حەزە ماددییەکانەوە، دووبارە لە منداڵدانی دایکدا لەدایک دەبنەوە؛ ئەوانەی ژیانێکی پڕ لە خراپەکارییان تێپەڕاندووە، لە دۆخێکی پڕ لە ژان، تاریکی و سزادا سەر لە نوێ سەرهەڵدەدەنەوە؛ لە بەرامبەردا، ئەوانەی خاوەن ڕەفتار و پاکژیی دەروونین، بەرەو دۆخ و کایەی پڕ لە شادومانی و ئاسوودەیی دەچن؛ بەڵام دۆخی باڵاترین هی کەمینەیەکی بێگەرد و کامڵە (عارفە ڕاستەقینەکان)، کە چیتر ناگەڕێنەوە بۆ هیچ کام لەم خولانە و ڕاستەوخۆ تێدەپەڕن بۆ ناو دۆخی کۆتایی و نەمر، واتە 'نیبانا'.",
  "127": "نە لە ئاسماندا، نە لە ناوەڕاستی ئۆقیانووسدا، و نە لە ئەشکەوتی چیاکاندا، هیچ شوێنێک لەسەر ئەم زەوییە نادۆزرێتەوە کە مرۆڤ تێیدا بمێنێتەوە و بتوانێت لە دەرئەنجامەکانی کارە خراپەکانی خۆی ڕزگاری بێت.",
  "128": "نە لە ئاسماندا، نە لە ناوەڕاستی ئۆقیانووسدا، و نە لە ئەشکەوتی چیاکاندا، هیچ شوێنێک لەسەر ئەم زەوییە نادۆزرێتەوە کە مرۆڤ تێیدا بمێنێتەوە و مردن بەسەریدا زاڵ نەبێت.",
  "chap10": "تەمبێکردن و سزا",
  "129": "هەموو بوونەوەرێک لە بەرامبەر دار، توندوتیژی و سزای جەستەییدا دەلەرزێت و کڕکەم دەکات، چونکە ترس لە ئازار لە ناخی هەموواندا هەیە؛ بە هەمان شێوە، هەموو گیاندارێک لە مردن و لەدەستدانی ژیان دەترسێت. کاتێک مرۆڤ بە قووڵی لەم حەقیقەتە تێ دەگات، کەسانی تر بە بەراورد لەگەڵ ناخی خۆیدا دەبینێت؛ بۆیە لەسەر بنەمای ئەم هاوسۆزییە، خۆی لە زیان گەیاندن و لێدانی کەسانی تر دەپارێزێت و نابێتە هۆکار یان هاندەر بۆ ئەوەی هیچ کەسێکی تریش تووشی ئازار و توندوتیژی ببێتەوە.",
  "130": "هەموو بوونەوەرێک لە بەرامبەر توندوتیژی و سزا دەلەرزێت و پێی تێک دەچێت، چونکە حەزی مانەوە و خۆشویستنی ژیان لە ناخی هەموواندا وەک یەکە؛ ژیان بۆ هەموو تاکێک شیرین، ئازیز و بەهادارە. کاتێک مرۆڤ بە ئاگاییەوە ئەوانی تر لەگەڵ خۆیدا بەراورد دەکات و تێ دەگات کە هیوای ئەوانیش بۆ ژیان ڕێک وەک هیوای خۆیەتی، ئەوا نە خۆی دەستپێشخەر دەبێت لە ئازاردان و لێدانی کەس، و نە ڕێگە بە خۆی دەدات ببێتە هۆکار یان هاندەر بۆ ئەوەی کەسانی تر ڕووبەڕووی توندوتیژی و سزادان ببنەوە.",
  "131": "هەر کەسێک، بۆ بەدەستهێنانی بەختەوەریی خۆی، ئازاری بوونەوەرانی تری چێژخواز بدات، لە پاشەڕۆژدا (لە ژیانی داهاتوودا) چێژ لە چاکە و بەختەوەری نابینێت.",
  "132": "هەر کەسێک، بۆ بەدەستهێنانی بەختەوەریی خۆی، ئازاری بوونەوەرانی تری چێژخواز نەدات، لە پاشەڕۆژدا (لە ژیانی داهاتوودا) چێژ لە چاکە و بەختەوەری دەبینێت‌.",
  "133": "نابێت بە زبری، توندی یان بە شێوازێکی بریندارکەر قسە لەگەڵ هیچ کەسێکدا بکەیت، چونکە مرۆڤەکان لە بەرامبەر سووکایەتی و قسەی ڕەقدا بێدەنگ نابن و بە هەمان شێواز وەڵامت دەدەنەوە. وتەی پڕ لە کینە و تۆڵەسەندنەوە، لە ناخدا ئازارێکی قووڵ بەجێ دەهێڵێت و کۆتاییەکەی تەنها دروستبوونی گرژییە؛ کاتێکیش قسەی ناخۆش و زبر لە نێوان لایەنەکاندا دەگۆڕدرێتەوە، ململانێکە لە کێشەی زمانەوانییەوە دەگۆڕێت بۆ پێکدادانی جەستەیی، کە دواجار دەبێتە هۆی برینداربوون و زیان گەیاندن بە خۆت.",
  "134": "ئەگەر وەک زەنگێکی درزبردوو (یان تێکشکاو) خۆت بێدەنگ بکەیت، ئەوا پێشوەخت گەیشتوویتەتە 'نیبانا': چونکە هیچ جۆرە مەیلی تۆڵەسەندنەوەیەک لە تۆدا بەدی ناکرێت.",
  "135": "ڕێک وەک چۆن شوانێک بە گۆچانەکەی مانگاکانی بەرەو لەوەڕگا دەبات، بە هەمان شێوە پیری و مردن، ژیانی بوونەوەرەکان بەرەو کۆتایی ڕادەماڵن.",
  "136": "کاتێک مرۆڤی نەزان کردەوەی چەوت ئەنجام دەدات، درک بە سروشتی پیسی کارەکەی ناکات؛ بەڵام ئەو مرۆڤە کەمئەقڵە بەهۆی کردەوەکانی خۆیەوە ئەشکەنجە دەدرێت، ڕێک وەک کەسێک کە بە ئاگر بسووتێت.",
  "137": "هەر کەسێک بە هێز، دار یان توندوتیژی، ئازار و زیان بە کەسێک بگەیەنێت کە بێدەسەڵاتە، چەکی پێ نییە و هیچ زیان یان ئازارێکی بۆ دەوروبەرەکەی نەبووە، ئەوا ئەو مرۆڤە ستەمکارە بەهۆی کاردانەوەی سروشتیی کردەوەکەیەوە، زۆر بە خێرایی لە ژیانیدا تووشی یەکێک لەو دە دۆخە سەخت و وێرانکەرانە دەبێت کە لە خاڵەکانی داهاتوودا (١٣٨-١٤٠) باس کراون.",
  "138": "ڕووبەڕووی ئازاری توند، کارەسات، زیانی جەستەیی، یان تەنانەت نەخۆشیی سەخت، یان لەدەستدانی هۆش، یان چەوساندنەوە لە لایەن پادشاوە،",
  "139": "یان تۆمەتی قورس، یان لەدەستدانی خزم و کەسوکار، یان لەناوچوونی سامان،",
  "140": "یان ئاگرێکی وێرانکەر دەبێتەوە کە ماڵەکەی دەسووتێنێت. لە کاتی هەڵوەشانەوەی جەستەشیدا (دوای مردن)، ئەو مرۆڤە بێ ئاگایە لە دۆزەخدا لەدایک دەبێتەوە.",
  "141": "نە بە ڕووتی گەڕان، نە قژی ئاڵۆز و شۆڕ، نە چڵکنی، نە ڕۆژووی توند، نە پاڵکەوتن لەسەر زەوی، نە خۆڵاویبوون، نە خۆڵەمێش، و نە دانیشتن لەسەر پاژنەی پێ بە مەبەستی ڕیازەت، ناتوانن مرۆڤێکی فانی پاک بکەنەوە ئەگەر بەسەر گومانەکانیدا سەرنەکەوتبێت.",
  "142": "تەنها ئەگەر بە جلی ڕازاوەشەوە بێت، ئەگەر لە ئاشتیدا بژی، شەهوەتەکانی ڕامکردبێت، هەستەکانی کۆنترۆڵ کردبێت، هۆشیار بێت لە چوار ڕێگای باڵای عارفان، بە تەواوی پاک بێت، و ئازار و سزای بەرامبەر بە تەواوی بوونەوەرە زیندووەکان وەلا نابێت، ئەوا بە ڕاستی ئەو 'برامانا'یە، ئەو زاهیدە، ئەو 'بهیکهوو'یە (مەزهەبی ڕاستەقینەیە).",
  "143": "لەم جیهانەدا زۆر بە دەگمەن کەسێک دەدۆزرێتەوە کە خاوەنی ئاستێکی ئەوتۆ لە حەیا، شەرم و وریایی دەروونی بێت کە پێشوەختە و بەهۆی بەئاگا بوونی خۆیەوە، خۆی لە هەڵە و کردەوەیەک بپارێزێت کە ببێتە هۆی لۆمەکردن و سەرزەنشتکردنی لە لایەن دەوروبەرەوە. ئەم جۆرە مرۆڤە وەک ئەسپێکی ڕەسەن و ڕاهێنراو وایە کە پێش ئەوەی قامچییەکە بە جەستەی بکەوێت، تەنها بە بینین یان هەستپێکردنی سێبەری قامچییەکە، خۆی ڕاست دەکاتەوە و بە ڕێگای دروستدا دەڕوات، بەبێ ئەوەی پێویستی بە لێدان یان سزادانی ڕاستەقینە هەبێت بۆ ئەوەی بێتەوە سەر ڕێگا.",
  "144": "وەک ئەسپێکی ڕەسەن کە قامچی لێ دەدرێت، هۆشیار و بەپەرۆش بە. بەهۆی متمانە، ڕەوشت، هەوڵ و کۆشش، قووڵبوونەوە (مێدیتەیشن)، لێکۆڵینەوە لە حەقیقەت، بەهرەمەندبوون لە زانست و ڕەفتار، و بە ئاگا بوون، خۆت لەم ئازارە مەزنە (سامسارا) ڕزگار بکە.",
  "145": "ئاودێران ئاو ئاڕاستە دەکەن. تیرسازان تیر ڕاست دەکەنەوە. دارتاشان دار دەچەمێننەوە و دایدەتاشن. کەسانی خاوەن فەزیلەتیش خۆیان کۆنترۆڵ دەکەن.",
  "chap11": "پیری",
  "146": "پێکەنین چییە و شادی کامەیە کاتێک ئەم جیهانە بە بەردەوامی [لە ئاگری حەز، کینە و نەزانیندا] دەسووتێت؟ کاتێک بە تەواوی لە ناو تاریکیدا نوقم بوون، ئایا ناگەڕێن بەدوای ڕووناکیدا؟",
  "147": "تەماشای ئەم جەستە ڕازاوەیە بکە؛ تۆپەڵەیەکە لە زام و برین، کۆمەڵە ئێسکێکی پێکەوەنراوی نەخۆشە، کە زۆری پێدا هەڵدەگوترێت و بایەخی پێ دەدرێت، بەڵام هیچ جێگیری و مانەوەیەکی تێدا نییە و چرکەیەک وەک خۆی نامێنێتەوە.",
  "148": "ئەم جەستەیە بە تەواوی داڕزاو و فشۆڵە؛ هێلانەیەکی کەنەفت و پڕ لە نەخۆشییە کە بەرەو لەناوچوون دەچێت. ئەم بارستاییە گەنیوە لەبەریەک هەڵدەوەشێت و شی دەبێتەوە؛ بە ڕاستی کۆتایی تاقانەی ژیان تەنها مردنە.",
  "149": "ئەم ئێسکە سپی و خۆڵەمێشییانەی مرۆڤ کە دوای مردن بەجێ دەمێنن، ڕێک وەک ئەو کوولەکە گەیوانە وان کە لە وەرزی پاییزدا وشک دەبن و بە بێکارەیی لە کێڵگەکاندا فڕێ دەدرێن؛ کاتێک کۆتایی جەستە تەنها کۆمەڵێک ئێسکی ڕزیوی فڕێدراو بێت، ئیتر تەماشاکردن و سەرنجدانی، چ چێژ و خۆشییەکی تێدا بەدی دەکرێت؟",
  "150": "ئەم [جەستەیە] شارێکە لە ئێسک دروستکراوە، کە بە گۆشت و خوێن سواغ دراوە. لە ناخی ئەم شارەدا پیری، مردن، فیز (لوتبەرزی) و کینە و غەیبەت حەشار دراون.",
  "151": "تەنانەت گالیسکە پاشایەتییە نەخشێنراوەکانیش کۆن دەبن و تێک دەچن. بە هەمان شێوەش جەستە بەرەو پیری و پووکی دەچێت. بەڵام 'دەهاما' (یاسا و حەقیقەتی) پاکان و چاکان هەرگیز کۆن نابێت؛ چاکەکاران بەم شێوەیە حەقیقەت لە نێوان خۆیاندا دەگوازنەوە.",
  "152": "ئەو مرۆڤەی زانین و فێربوونی کەمە، وەک گایەک وایە کە بەرەو پیری دەچێت؛ تەنها گۆشت و ماسولکەکانی گەورە دەبن، بەڵام حیکمەت و داناییەکەی گەشە ناکات.",
  "153": "لە نێوان چەندین لەدایکبووندا لە ناو خولی سەرگەردانیی (سامسارا)دا خولامەوە، بەدوای بنیادنەری ئەم خانووەدا (خالق یان هۆکاری دروستبوونی جەستە و حەزەکان) دەگەڕام بەبێ ئەوەی بیدۆزمەوە؛ چەندە پڕ لە ژان و ئازارە کە مرۆڤ دووبارە و دووبارە لەدایک ببێتەوە.",
  "154": "ئەی بنیادنەری خانوو! دواجار بینیمیت و تۆم ناسیەوە. چیتر ناتوانیت ئەم خانووە (جەستە) بنیاد بنێیتەوە. هەموو ڕاگیر و کۆڵەکەکانی پشتت شکان. کلیلەی بنمیچەکەت تێکشکێنرا. مێشکم گەیشتە دۆخی ڕەها و نەبەستراوە، و کۆتایی بە تینوێتی و حەزەکان (خواستن) هێنرا.",
  "155": "ئەو کەسانەی لە تەمەنی گەنجی و هێزدا ژیانێکی بە ئاگا و پیرۆزیان بەسەر نەبردووە، و چاکە یان داناییەکی ئەوتۆیان کۆ نەکردووەتەوە کە لە کاتی پیریدا پشتی پێ ببەستن، لە کۆتایی تەمەنیاندا کز و پەککەوتە دەبن؛ ئەوان ڕێک وەک مراوی یان شاهۆزە پیرەکانی کەنار گۆمێکی وشکبووی بێ ماسی وان، کە چاویان لە ئاوەکەیە بەڵام چیدی نە هێزی ڕاوکردنیان ماوە و نە ماسییەک هەیە تینوێتی و برسیێتیی ناخیانی پێ بشکێنن، تەنها بە بێدەسەڵاتی کڕ دەکەون و لە ناو دەچن.",
  "156": "ئەو کەسانەی ژیانێکی پیرۆزیان بەسەر نەبردووە، و لە گەنجێتیاندا هیچ سامانێکیان بەدەست نەهێناوە، وەک کەوانی کۆن و ڕزیو و بێ کەڵکەکان، شل و شۆق کەوتوون، و تەنها ناڵە و ئۆف بۆ ڕابردووی خۆیان دەکێشن.",
  "chap12": "خۆیی",
  "157": "ئەگەر مرۆڤ خۆی بە لاوە ئازیز و هێژا بێت، دەبێت زۆر بە باشی خۆی بپارێزێت و ئاگاداری ناخی بێت. دانا و هۆشیارەکان لە هەر یەکێک لە سێ بەشی شەودا [مەبەست قۆناغەکانی گەنجێتی، ناوەندی تەمەن و پیرییە] دەبێت بە ئاگا بن و چاودێری خۆیان بکەن.",
  "158": "پێویستە مرۆڤ سەرەتا خۆی لەسەر بنەمای ڕاست و دروست جێگیر بکات و ناخی ڕێک بخات، پاشان دەست بکات بە ئامۆژگاری و ڕێنماییکردنی ئەوانی تر. دانایەک کە بەم شێوەیە ڕەفتار بکات، هەرگیز تووشی لادان و گۆشەگیری [پیسبوونی دەروونی] نابێت.",
  "159": "مرۆڤ چۆن ئامۆژگاری دەوروبەرەکەی دەکات، دەبێت خۆشی ڕێک بەو شێوەیە کار بکات. تەنها کاتێک کە خۆی بە تەواوی کۆنترۆڵ کردووە، دەتوانێت ڕێنمایی [کۆنترۆڵی] ئەوانی تر بگرێتە دەست؛ چونکە لغاوکردن و کۆنترۆڵکردنی خود، بە ڕاستی قورسترین کارە.",
  "160": "مرۆڤ خۆی تەنها خۆی ڕزگارکەر و پەناگەی خۆیەتی، چونکە چ ڕزگارکەرێکی تر لە دەرەوەی خۆی هەیە کە هانای بۆ ببات؟ کاتێک مرۆڤ بە تەواوی ناخی خۆی لغاو و کۆنترۆڵ دەکات، ئەوا دەگاتە ئەو ڕزگارکەرە ناوەکییەی کە بە دەگمەن لە جیهاندا دەدۆزرێتەوە.",
  "161": "خراپە تەنها لە لایەن خودی مرۆڤەکەوە ئەنجام دەدرێت؛ لە ناخی خۆیەوە سەرچاوە دەگرێت و خۆی هۆکارەکەیەتی. ئەم خراپەیە مرۆڤی نەزان و بێ ئاگا دەهاڕێت و تێکی دەشکێنێت، ڕێک وەک چۆن ئەڵماسێک ڕەقترین گەوهەر دەبڕێت و دەیهاڕێت.",
  "162": "ئەو کەسەی کە بە تەواوی نوقمی گەندەڵی، داڕووخانی ناوەکی و خوە خراپەکان بووە، ڕێک وەک گژوگیایەکی بێگانەی پێچاوپێچ (مالوڤا) وایە کە لە بنکی دارێکی گەورە و بەهێز (سال) شین دەبێت و هێدی هێدی لێی دەئاڵێت؛ ئەم ڕوەکە داگیرکەرە هێندە بە توندی لە قەدی دارەکە توند دەکات و شیرەکەی دەمژێت تا بە تەواوی بەرگەکەی دەبڕێت و بەرەو وشکبوون و لە ناوچوونی دەبات. مرۆڤی گەندەڵیش بەم شێوازە، بەهۆی تەسلیمبوونی بە حەزە نزم وێرانکەرەکانی، بە دەستی خۆی کارێک بە ژیان و دەروونی خۆی دەکات کە تەنانەت سەرسەختترین دوژمنەکانیشی ناتوانن پێی بکەن و تەنها ئاواتی بۆ دەخوازن.",
  "163": "ئەنجامدانی ئەو کارانەی کە زیانبەخشن و هیچ قازانجێکی ڕاستەقینەیان بۆ خودی مرۆڤەکە نییە، زۆر ئاسانن؛ بەڵام ئەنجامدانی ئەو کارانەی کە بەسوود، چاک و خێرن، بە ڕاستی زۆر و زۆر دژوار و قورسن.",
  "164": "مرۆڤی نەفام کە بەهۆی دیدگا و تێگەیشتنە چەوتەکانییەوە، گاڵتە بە فێرکارییەکانی ئاراھانتەکان (مرۆڤە پاک و ڕۆشنبینەکان)، نەجیبزادەکان و ڕێبەرانی ڕاستی دەکات و ڕەتیان دەکاتەوە، کارەکەی ڕێک وەک قەسەب یان قامیشی (کاشتە) وا دەردەچێت؛ ئەم ڕوەکە کاتێک بەرگ دەگرێت و قۆزاخە و بەرهمەکەی پێ دەگات، ڕێک لەو کاتەدا لاسکەکەی وشک دەبێت و قەدی دەقڵیشێت، واتە بەرهمەکەی دەبێتە هۆی مردنی خۆی. بە هەمان شێوە، ئەو مرۆڤە گێلەش ئەو بیروباوەڕە چەوتانەی کە لە ناخیدا پەروەردەیان دەکات، کاتێک گەورە دەبن و بەرهم دەگرن، هیچ ئەنجامێکیان نابێت تەنها خێراکردنی داڕووخان و لە ناوچوونی خۆی نەبێت.",
  "165": "مرۆڤ تەنها بە کردەوەی خۆی تووشی خراپە دەبێت، و تەنها بەهۆی خۆیەوە گڵاو و پیس دەبێت. هەر بەهۆی کار و هۆشیاری خۆشییەوە واز لە خراپە دەهێنێت، و هەر بە خودی خۆشی پاک دەبێتەوە. پاکی و پیسی دەروون تەنها بەستراوە بە خودی مرۆڤەکەوە؛ هیچ کەس ناتوانێت کەسێکی تر پاک بکاتەوە.",
  "166": "مرۆڤ نابێت بەهۆی بەرژەوەندی و چاکەی ئەوانی ترەوە، هەرچەندە گەورەش بێت، بەرژەوەندی و گەشەی دەروونی خۆی پشتگوێ بخات. کاتێک بە ڕوونی لە ڕاستی و ئامانجی ڕزگاریی خۆت گەیشتی، ئەوا دەبێت بە تەواوی سەرنج و هێزت لەسەر بەدیهێنانی ئەو ئامانجە ناوەکییەی خۆت بێت.",
  "chap13": "جیهان",
  "167": "شوێنی ئامانجە نزم و بێبایەخەکان مەکەو. ژیان لە ناو بێ ئاگایی و غەفڵەتدا بەسەر مەبە. باوەش بۆ بیروباوەڕ و دیدگا چەوتەکان مەکەرەوە، و مەبە بەو کەسەی کە تەنها تینووی مانەوە و نوقمبوونە لە ناو جیهانی ماددیدا.",
  "168": "لە کاتی بەجێهێنانی ئەرکی [سەرگەردانی و سواڵکردنی ڕۆحی لەبەردەم دەرگای خەڵکدا بۆ بژێوی] خەمسارد مەبە. ئەم نەریتە بە تەواوی و بە وردی پەیڕەو بکە. هەر کەسێک ئەم ڕێکارە بە پاکی بپارێزێت، هەم لەم جیهانەدا و هەم لە جیهانی داهاتوودا بە ئاسوودەیی دەژی.",
  "169": "ڕێگای حەقیقەت و ڕەوشت بە تەواوی بپارێزە؛ هەرگیز بە ناپاکی و شلۆقی پەیڕەوی مەکە. ئەو کەسەی بە ڕاستگۆییەوە لەسەر ئەم ڕێگایە دەڕوات، هەم لەم جیهانە و هەم لە جیهانی داهاتوودا بە شادی دەژی.",
  "170": "ڕێک وەک چۆن مرۆڤ تەماشای بڵقێکی سەر ئاو دەکات، یان وەک چۆن سەرنجی ترووسکایی تەڵخ و خەڵەتێنەری سەرابێک دەدات؛ ئەگەر کەسێک بەم شێوازە [بێبایەخ و کاتی] تەماشای جیهان بکات، ئەوا پاشای مردن (یاما) ناتوانێت لێی تێ بگات و بیبینێتەوە.",
  "171": "وەرە و تەماشای ئەم جیهانە بکە کە وەک گالیسکەیەکی پاشایەتیی نەخشێنراو و ڕازاوە وایە؛ نەفامەکان لە ناو جوانییە ڕواڵەتییەکەیدا نوقم دەبن و سەرگەردان دەبن، بەڵام بۆ دانا و هۆشیارەکان، هیچ پەیوەستبوون و خولیاهەبوونێک بەم جیهانەوە بوونی نییە.",
  "172": "هەر کەسێک کە پێشتر بێ ئاگا و خەمسارد بووبێت، بەڵام پاشان بە ئاگا هاتبیێتەوە و وازی لە غەفڵەت هێنابێت؛ ئەو کەسە جیهان ڕووناک دەکاتەوە، ڕێک وەک مانگ کاتێک لە پشت هەورە تاریکەکانەوە دێتە دەرێ و دەدرەوشێتەوە.",
  "173": "هەر کەسێک بە کردەوەیەکی چاک، پەڵەی کارە خراپەکانی ڕابردووی دابپۆشێت و تێکیان بشکێنێت؛ ئەو کەسە ئەم جیهانە ڕووناک دەکاتەوە، ڕێک وەک چۆن مانگ لەژێر هەورەکان ڕزگاری دەبێت.",
  "174": "ئەم جیهانە نابینایە؛ تەنها کەسانێکی زۆر کەم هەن کە بە ڕوونی ڕاستییەکان دەبینن. ڕێک وەک چۆن لە ناو داوێکدا تەنها چەند باڵندەیەکی کەم دەتوانن خۆیان ڕزگار بکەن و بفڕن، بە هەمان شێوەش لەم جیهانەدا تەنها کەسانێکی زۆر کەم بەرەو دۆخی ڕزگاری و بەختەوەریی ڕەها دەچن.",
  "175": "قازە کێوییەکان لەسەر ڕێڕەوی خۆر دەفڕن. [ئەوانەی خاوەن هێزی دەروونین] بەهۆی هێزە ڕۆحییەکانیانەوە بە ئاسماندا دەڕۆن. دانایانیش بە تەواوی لەم جیهانە دەردەچن و ڕزگاریان دەبێت، دوای ئەوەی کە بەسەر 'مارا' (شەیتان) و سوپاکەیدا سەردەکەون.",
  "176": "مرۆڤێک کە درۆ دەکات و بە ئاسانی گرنگترین و تاکە یاسای مرۆڤایەتی (کە ڕاستگۆییە) پێشێل دەکات، و هیچ باک و باوەڕێکی بە دەرەنجامی کردەوەکانی لە داهاتوودا نییە، ئیتر هیچ سنوورێک بۆ وێرانکارییەکانی نامێنێت؛ لەبەر ئەوە، هیچ کارێکی قێزەون، ناپاکانە و خراپ لەم جیهانەدا نییە کە مرۆڤێکی لەو شێوەیە سڵ لە ئەنجامدانی بکاتەوە.",
  "177": "بە ڕاستی چاوچنۆک و ڕەزیلەکان ناچنە ناو کایە و جیهانە بەرزە ئاسمانییەکانەوە. مرۆڤی نەفام هەرگیز ستایشی بەخشندەیی ناکات. بەڵام مرۆڤی دانا بە بەخشین و دەستکراوەیی شادمان دەبێت، و بەهۆی ئەمەشەوە لە پاشاندا بە بەختەوەری دەگات.",
  "178": "گەیشتن بە یەکەم قۆناغی ڕزگاری (مەبەست دۆخی سۆتاپانا یان چوونە ناو ڕێڕەوی حەقیقەتە)، زۆر لەوە چاکتر و بەرزترە کە مرۆڤ ببێتە پاشای ڕەهای سەر زەوی، یان بچێتە بەهەشت، یاخود ببێتە سەرپەرشت و خودای هەموو جیهانەکان.",
  "chap14": "بوودا",
  "179": "ئەو زاتەی کە سەرکەوتنەکەی [بەسەر ئارەزووەکاندا] هەرگیز وەرناگێڕێت بۆ شکست، و هیچ کام لەو خولیایانەی کە بەسەریاندا سەرکەوتووە لەم جیهانەدا شوێنی ناکەون و ناتوانن بیگەڕێننەوە؛ ئەو بوودایەی کە خاوەن مەودایەکی بێپایانە و هیچ شوێنپێ و ڕێچکەیەکی [ماددی یان دەروونیی بۆ گرتنەوە] بەجێ نەهێشتووە، تۆ چۆن و بە کام ڕێگادا دەتوانیت ڕێنوێنی بکەیت یان تەڵەی بۆ بنێیتەوە؟",
  "180": "ئەو زاتەی کە چیدی هیچ ویستێک و خولیایەکی تێکئاڵو و سەر لێشێوێنەری تێدا نەماوە تا بەرەو ژیانێکی نوێ [یان خولگەی نوێی لەدایکبوونەوە] کێشی بکات؛ ئەو بوودایەی خاوەن مەودای بێپایان و بێ شوێن پێیە، تۆ چۆن و بە کام ڕێگادا دەتوانیت لە خشتەی ببەیت؟",
  "181": "ئەو دانایانەی کە بە تەواوی سەرنجیان لەسەر تێڕامان (مێدیتەیشن) جێگیر کردووە، و چێژ و شادی لە ئارامیی دەستبەرداربوون [واتە نیبانا/نیرڤانا] دەبینن؛ ئەو بوودا بە ئاگا و کامڵانە تەنانەت خوداوەندەکانیش بە زۆر ئازیز و هێژایان دەزانن.",
  "182": "لەدایکبوون لە شێوەی مرۆڤدا دەرفەتێکی زۆر دەگمەن و دژوارە (چونکە لە ناو سەرجەم بوونەوەراندا تەنها مرۆڤ خاوەنی ئەو هۆشیارییەیە کە بتوانێت پێی ڕزگار بێت). لە لایەکی ترەوە، ژیانی مرۆڤە فانییەکان کورت و پڕە لە سەختی و مەینەتی. لە ناو ئەم هەموو سەختییەشدا، ڕێککەوتنی بیستن و تێگەیشتن لە حەقیقەتی باڵا (دەهاما) زۆر ئەستەمە؛ چونکە دەرکەوتنی مرۆڤێکی تەواو ڕۆشنبیری وەک بوودا لە مێژوودا، ڕووداوێکی یەکجار دەگمەنە و لە هەموو سەردەمێکدا ڕوونادات.",
  "183": "ئەنجام نەدانی هیچ جۆرە خراپەیەک، پەروەردەکردن و گەشەپێدانی چاکە لە ناخدا، و پاککردنەوەی تەواوی عەقڵ و دەروون؛ ئەمەیە تەواوی فێرکاریی بووداکان.",
  "184": "بووداکان دەڵێن: لێبوردەیی و دان بەخۆداگرتن لە کاتی ڕووبەڕووبوونەوەی ناخۆشییەکاندا، باڵاترین و بەهێزترین شێوازی خۆچەوساندنەوەی ڕۆحییە؛ هەروەها گەیشتن بە دۆخی 'نیبانا' (ئارامیی ڕەها و نەمانی ویست) بەرزترین ئامانجە. لەبەر ئەوە، ئەو کەسەی کە ئازاری گیاندارێک یان مرۆڤێکی تر دەدات، بە هیچ شێوەیەک ناچێتە ڕیزی گۆشەگیر و ڕێبوارانی ڕاستی؛ و هەر کەسێکیش ستەم و چەوساندنەوە بەرامبەر بە ئەوانی تر پەیڕەو بکات، ناتوانرێت پێی بگوترێت زاهیدێکی ڕاستەقینەی ڕۆحی.",
  "185": "جنێو نەدان و سووکایەتی نەکردن، ئازار نەگەیاندن، ڕێزگرتن و پابەندبوون بە یاسا ئەخلاقییە بنەڕەتییەکان، میانڕەوی لە خواردندا، پەنابردن بۆ شوێنی گۆشەگیر و بێدەنگ، و قوڵبوونەوە لە ناو بیرکردنەوە و تێڕامانە باڵاکاندا؛ ئەمەیە فێرکاریی بووداکان.",
  "186": "تەنانەت ئەگەر بارانیش لە سکەی زێڕ ببارێت، تێربوون و تەسلیمبوون بە چێژە جەستەیی و دونیاییەکان نایەتە دی. چێژە هەستیارەکان شیرینییەکی زۆر کەم و کاتییان هەیە، بەڵام لە ناخیاندا پڕن لە ئازار و مەینەتی. دانایان بەم ڕاستییە دەزانن، بۆیە تەنانەت چێژ و خۆشییە ئاسمانییەکانیش فریویان نادەن.",
  "187": "مریدی ئەو زاتەی کە بە تەواوی ڕۆشن بووە (بوودا)، تەنها شادمان دەبێت بە تێکشکاندن و لە ناوبردنی تەواوەتیی ویست و ئارەزووەکان.",
  "188": "مرۆڤەکان کاتێک دڵیان پڕ دەبێت لە ترس و دڵەڕاوکێ، پەنا بۆ زۆر شوێن دەبەن و دەیانکەن بە حەشارگەی خۆیان؛ وەک چیاکان، دارستانەکان، باخەکان، دارە پیرۆزەکان و پەرستگەکان.",
  "189": "بەڵام نەخێر، هیچ کام لەم شوێنانە پەناگەیەکی ئارام و بێوەی نین، و هیچ کامیشیان باڵا و ڕەها نین. مرۆڤ بە پەنابردن بۆ ئەم جۆرە حەشارگە دەرەکییانە، هەرگیز لە خەم و تەواوی مەینەتییەکانی ژیان ڕزگاری نابێت.",
  "190": "بەڵام ئەو کەسەی کە پەنا دەباتە بەر بوودا (ڕێبەرەکە)، دەهاما (حەقیقەت و فێرکارییەکە)، و سانگها (کۆمەڵگەی ڕۆشنبینان)، و بە زانیاری و تێگەیشتنێکی ڕاست و درستەوە سەیری چوار ڕاستییە نەجیبزادەکە دەکات",
  "191": "کە بریتین لە: [ئازار و مەینەتی، سەرچاوە و هۆکاری ئازار، تێپەڕاندن و کۆتاییهێنان بە ئازار، و ئەو ڕێگا هەشت قۆناغییە نەجیبزادەیەی کە دەبێتە هۆی وەستاندنی تەواوەتیی ئازار]؛ بە ڕاستی ئەمە پاکترین و پارێزراوترین پەناگەیە.",
  "192": "ئەمە باڵاترین حەشارگەیە. مرۆڤ تەنها بە گەڕان بەدوای ئەم پەناگەیەدا، لە هەموو خەم و مەینەتییەکانی بوون ئازاد دەبێت.",
  "193": "دۆزینەوەی مرۆڤێکی خاوەن داناییەکی وا باڵا و گەورە زۆر قورسە؛ مرۆڤی ئاوا لە هەموو شوێنێک لە دایک نابێت. لە هەر شوێن و خێزانێکدا کە دانایەکی لەو شێوەیە لە دایک ببێت، ئەو بنەماڵەیە بەرەو گەشە و بەختەوەرییەکی ڕاستەقینە هەنگاو دەنێت.",
  "194": "لەدایکبوونی بووداکان سەرچاوەی شادییە. فێرکردنی دەهامای باڵا و پاک شادی بەخشە. یەکێتی و تەبایی سانگها (کۆمەڵگەی پێگەیشتووان) شادییە، و خود دیسپلینی و یەکگرتوویی ئەو کەسانەی پێکەوەن، هۆکاری بەختەوەرییە.",
  "195": "ئەو کەسەی کە ڕێز و شکۆ دەبەخشێت بەو زاتانەی کە شایستەی ڕێزن، چی بووداکان بن یان مریدەکانیان؛ ئەو کەسانەی کە بەسەر کۆسپەکاندا سەرکەوتوون و خۆیان لە خەم و شیوەن ڕزگار کردووە،",
  "196": "پاداشت و گەورەیی ڕۆحیی ئەو کەسەی کە ڕێز لەم زاتە ئارام و بێ ترسانە دەگرێت، بە هیچ پێوەرێک ناپێورێت و ناتوانرێت سنووردار بکرێت.",
  "chap15": "بەختەوەری",
  "197": "ئاخ، چەند کارێکی مەزن و بەختەوەرییەکی قووڵە کاتێک ئێمە لە ناو کۆمەڵگە و ژینگەیەکدا دەژین کە پڕە لە مرۆڤی کینە لەبەر و ڕق ئەستوور، بەڵام ناخی خۆمان لەو ڕق و کینەیە پاراستووە و هیچ شوێنەوارێکی تێدا نییە؛ کاتێک لە ناو مرۆڤە نەرێنی و ناتەباکاندا نشینگەمان دەگرین، ئێمە بە دڵێکی بێگەرد، هێمن و ئاشتیخوازەوە لە نێوانیاندا دەمێنینەوە.",
  "198": "ئاخ، چەن بە بەختەوەری دەژین بە لەشساغی لە ناو کەسانی نەخۆشدا [مەبەست لە نەخۆشیی دەروونی و شەهوەتە]؛ لە ناو مرۆڤە نەخۆشەکاندا، ئێمە بە لەشساغی و تەندروستیی ڕۆحییەوە دەژین.",
  "199": "ئاخ، چەن بە بەختەوەری دەژین بە بێ خولیا و پەرۆشی [بۆ چێژە هەستیارەکان] لە ناو ئەو کەسانەی کە تینووی ئەو چێژانەن؛ لە ناو پەرۆش و تینووەکاندا، ئێمە بێ خولیا و تینوویەتی دەژین.",
  "200": "ئاخ، چەن بە بەختەوەری دەژین ئێمە کە هیچ کۆسپ و بەربەستێک [گرێی دەروونی] لە ناخماندا نییە. ئێمە لە شادیدا بەخێو دەکرێین و دەبینە خۆراکت‌دەری خۆشی، ڕێک وەک خوداوەندەکانی کایەی ڕووناکی (ئاب‌هەسسارا).",
  "201": "سەرکەوتن کینە و ڕق دەخاتەوە، چونکە بەزێنراوەکان لە ناو ئازاردا دەژین. بەڵام ئاشتیخواز و هێمنەکان بە بەختەوەری دەژین، چونکە دەستبەرداری سەرکەوتن و شکست بوون.",
  "202": "هیچ ئاگر و هێزێکی سووتێنەر نییە کە وەک ئاگری شەهوەت و ویستی توند ناخی مرۆڤ بکات بە خۆڵەمێش، و هیچ تاوان و وێرانکارییەکیش نییە کە بگاتە ئاستی ئەو زیانەی ڕق و کینە بە مرۆڤایەتی دەگەیەنێت. لە لایەکی ترەوە، هیچ بارگرانی و دەردێک گەورەتر نییە لە خاوەندارێتی جەستەی ماددی (چونکە سەرچاوەی سەرەکیی نەخۆشی، پیری و ئازارە)، و هیچ شادی و بەختەوەرییەکیش لە گەردووندا نییە کە بەرزتر و باڵاتر بێت لە گەیشتن بە ئارامیی ڕەها و نەمانی ئازار (نیبانا).",
  "203": "برسییەتی گەورەترین نەخۆشییە. پێکهێنەرەکانی بوون (ئەگریگەیتەکان/خەمۆکەکان) گەورەترین دەردن. کاتێک دانایان بەم ڕاستییە وەک خۆی دەزانن، ئەوا دەگەنە 'نیبانا' کە باڵاترین بەختەوەرییە.",
  "204": "تەندروستی [پاکیی دەروون] گەورەترین دەستکەوتە. قەناعەت و ڕازیبوون گەورەترین سەرمایەیە. کەسانی جێگای متمانە باشترین خزم و دۆستن. 'نیبانا'ش باڵاترین بەختەوەرییە.",
  "205": "پاش چەشتنی تامی گۆشەگیری و تامی هێوربوونەوە، مرۆڤ لە ناسۆر و چڵکی دەروون ڕزگاری دەبێت، کاتێک تامی شادیی حەقیقەت [دەهاما] دەنۆشێت.",
  "206": "بینینی مرۆڤە پاک و نەجیبزادەکان (ئاریاکان) چاکە؛ هاوڕێیەتی و یاوەریی ئەوان هەمیشە بەختەوەرییە. مرۆڤ ئەگەر نەفامەکان نەبینێت، دەکرێت هەمیشە بەختەوەر بێت.",
  "207": "بە ڕاستی ئەو کەسەی لەگەڵ نەفامەکاندا هاودەم دەبێت، بۆ ماوەیەکی درێژ تووشی خەم و پەژارە دەبێت. تێکەڵاوبوون لەگەڵ نەفامەکاندا هەمیشە بە ئازارە، ڕێک وەک هاوەڵیکردنی دوژمن. بەڵام تێکەڵاوبوون لەگەڵ دانایاندا بەختەوەرییە، ڕێک وەک گەیشتنەوە بە خزم و دۆستانی ئازیز.",
  "208": "لەبەر ئەوە: پێویستە مرۆڤ لەگەڵ مرۆڤی تێگەیشتوو، دانا، زانا، خۆڕاگر، بەئەمەک و پاکدا (ئاریا) هاوەڵی بکات؛ پێویستە مرۆڤ شوێن کەسێکی خاوەن فەزیلەت و ژیریی لەو شێوەیە بکەوێت، ڕێک وەک چۆن مانگ شوێن ڕێڕەوی ئەستێرەکان دەکەوێت.",
  "chap16": "خۆشەویستی و دڵبەستەیی",
  "209": "ئەو کەسەی خۆی خەریک دەکات بەوەی کە پێویستە لێی دوور بکەوێتەوە، و پشتگوێی دەخات ئەوەی کە پێویستە پەیڕەوی بکات، و واز لە گەڕان بەدوای حەقیقەتدا دەهێنێت؛ کاتێک تەنها ڕاووڕاوێنی چێژە کاتییەکان دەکات، پاشان چاوچنۆکی و ئیرەیی بەو کەسانە دەبات کە لە پێناو گەشەی ڕۆحیدا تێدەکۆشن.",
  "210": "هاودەمی و تێکەڵاوبوونی قووڵ مەکە لەگەڵ ئەوانەی کە خۆشت دەوێن [دڵبەستەیانت]، و هەرگیز تێکەڵاویش مەبە لەگەڵ ئەوانەی کە خۆشت ناوێن؛ چونکە نەبینینی ئەوانەی کە خۆشت دەوێن بە ئازارە، و بینینی ئەوانەش کە حەزت پێیان نییە، هەر خەم و ئازارە.",
  "211": "لەبەر ئەوە، دڵبەستەی هیچ شتێک مەبە، چونکە جیابوونەوە لەوەی کە خۆت پێوە گونجاندووە و پێت ئازیزە، زۆر دژوار و خراپە؛ بۆ ئەو کەسانەی کە هیچ شتێکیان بە لاوە ئازیز یان بێبایەخ نییە [واتە تێپەڕینیان لە دوو جەمسەریی حەز و ڕق کردووە]، هیچ کۆت و زنجیرێکی دەروونی بوونی نییە.",
  "212": "لە ناخی ئازیزکردن و خۆشەویستییەوە خەم سەرچاوە دەگرێت، لە ئازیزکردنەوە ترس شین دەبێت؛ بۆ ئەو کەسەی کە بە تەواوی لەم تەڵەی ئازیزکردنە ئازاد بووە، هیچ خەمێک بوونی نییە، چ بگات بە ترس.",
  "213": "لە ناخی سۆز و دڵبەستەیییەوە خەم سەرچاوە دەگرێت، لە سۆزەوە ترس شین دەبێت؛ بۆ ئەو کەسەی کە بە تەواوی لەم سۆز و خولیایە ئازاد بووە، هیچ خەمێک بوونی نییە، چ بگات بە ترس.",
  "214": "لە ناخی پەیوەستبوونی دەروونییەوە [بە ماددە و کەسەکانەوە] خەم سەرچاوە دەگرێت، لە پەیوەستبوون ترس شین دەبێت؛ بۆ ئەو کەسەی کە بە تەواوی لە پەیوەستبوون ئازاد بووە، هیچ خەمێک بوونی نییە، چ بگات بە ترس.",
  "215": "لە ناخی شەهوەت و حەزی توندەوە خەم سەرچاوە دەگرێت، لە شەهوەتەوە ترس شین دەبێت؛ بۆ ئەو کەسەی کە بە تەواوی لە شەهوەتدا ئازاد بووە، هیچ خەمێک بوونی نییە، چ بگات بە ترس.",
  "216": "لە ناخی ویست و تینووێتیی دەروونییەوە خەم سەرچاوە دەگرێت، لە ویستەوە ترس شین دەبێت؛ بۆ ئەو کەسەی کە بە تەواوی لەم ویستە (تانها) ئازاد بووە، هیچ خەمێک بوونی نییە، چ بگات بە ترس.",
  "217": "هەر کەسێک کە لە فەزیلەت و تێڕوانینی ناوەکیدا کامڵ بێت، لەسەر بنەمای حەقیقەت (دەهاما) جێگیر بووبێت، ڕاستییەکانی ناسیبێت، و ئەرکە ڕۆحییەکانی خۆی بەجێ بهێنێت؛ خەڵکی بە هێژا و ئازیزی دەزانن.",
  "218": "ئەو کەسەی خولیایەکی توندی تێدا ڕواوە بۆ گەیشتن بەو دۆخەی کە بە زمان و وەسف دەرنابڕێت [واتە نیبانا]، ئەو کەسەی عەقڵ و ناخی بە سێ بەرهمەکەی ڕزگاری لەرزیوە و شاد بووە، و هۆشیارییەکەی بە چێژە ماددییەکانەوە بەند نەکراوە؛ بەو کەسە دەگوترێت 'ڕێبواری دژە ڕەوت' [ئەو کەسەی کە پێچەوانەی شەپۆلی ئارەزووەکانی جیهان مەلە دەکات بەرەو سەرچاوە].",
  "219": "کاتێک پیاوێک بۆ ماوەیەکی درێژ ون دەبێت و لە دوورەوە بە سەلامەتی دەگەڕێتەوە، خزم و دۆست و خەمخۆرەکانی کاتی گەیشتنی، بە گەرمی پێشوازی لێ دەکەن و شاد دەبن.",
  "220": "بە هەمان شێوە، کاتێک مرۆڤی چاکەکار لەم جیهانە کۆچ دەکات و دەچێتە جیهانی داهاتوو، کردەوە چاکەکانی بە گەرمی پێشوازی لێ دەکەن؛ ڕێک وەک چۆن خزمەکان پێشوازی لە ئازیزێکیان دەکەنەوە کاتێک لە سەفەر دەگەڕێتەوە.",
  "chap17": "توڕەیی",
  "221": "پێویستە مرۆڤ دەستبەرداری توڕەیی بێت. پێویستە فیز و لەخۆباییبوون تێک بشکێنێت. دەبێت بەسەر سەرجەم کۆت و زنجیرەکانی دەروونیدا سەربکەوێت. ئەو کەسەی کە دڵبەستەی کایەی عەقڵ و جەستەی ماددی نابێت و چیدی چڵکی ئارەزووی تێدا نەماوە، هیچ دەرد و مەینەتییەکی بوون تووشی نابێت.",
  "222": "هەر کەسێک بتوانێت ڕێگری لە تەوژمی توڕەیی هەڵچووی ناخی بکات، ڕێک وەک چۆن کۆنترۆڵی گالیسکەیەکی تیژڕەوی لە دەست دەرچوو دەکرێت؛ من تەنها بەو کەسە دەڵێم گالیسکە لێخوڕی ڕاستەقینە. گالیسکەلێخوڕەکانی تر تەنها جڵەوگرن (واتە تەنها پەتەکەیان بە دەستەوەیە بێ ئەوەی هێزی ڕاگرتنیان هەبێت).",
  "223": "بە سۆز و خۆشەویستی بەسەر توڕەییدا سەربکەوە. بە چاکە و نەرمونیانی وێرانکاریی خراپە تێک بشکێنە. بە بەخشین و دەستکراوەیی بەسەر مرۆڤی چاوچنۆک و ڕەزیلدا سەربکەوە، و بە حەقیقەت و ڕاستگۆیی کۆتایی بە درۆی درۆزن بهێنە.",
  "224": "پێویستە مرۆڤ تەنها ڕاستی دەربڕێت. پێویستە ڕێگا نەدات توڕەیی کۆنترۆڵی بکات. پێویستە تەنانەت لە کاتی کەمبوونی دارایی و تەنگانەیشدا، بەشێک ببەخشێت بەو کەسەی کە داوای لێ دەکات. مرۆڤ بە پەیڕەوکردنی ئەم سێ ڕێگایە، دەگاتە کایە بەرزەکانی خوداوەندەکان.",
  "225": "ئەو دانا و حەکیمانەی کە بێ ئازارن و هەمیشە جەستەی خۆیان لە خراپەکاری پاراستووە، بەرەو دۆخی نەمر و نەبڕاوە (نیبانا) هەنگاو دەنێن؛ ئەو شوێنەی کاتێک تێیدا جێگیر دەبن، چیدی هیچ خەم و پەژارەیەک ناناسن.",
  "226": "ئەو کەسانەی هەمیشە بە ئاگا و هۆشیارن، و شەو و ڕۆژ خەریکی خۆ دیسپلینکردن و ڕاهێنانی دەروونی خۆیانن، و بە تەواوی ڕوویان لە دۆخی ئارامیی ڕەهایە (نیبانا)؛ سەرجەم پیسی و چڵکە دەروونییەکانیان لە ناو دەچن و نامێنن.",
  "227": "ئەی ئاتوال، ئەمە وتەیەکی زۆر کۆنە و تەنها هی ئەمڕۆ نییە: خەڵکی لۆمەی ئەو کەسە دەکەن کە بە بێدەنگی دادەنیشێت، لۆمەی ئەو کەسەش دەکەن کە زۆر قسە دەکات. تەنانەت ئەوەش کە کەم قسە دەکات، هەر لۆمەی دەکەن. لەم جیهانەدا هیچ کەسێک نییە کە لە ژێر تیغی لۆمە و ڕەخنەی خەڵکیدا ڕزگاری بووبێت.",
  "228": "هەرگیز لە ڕابردوودا نەبووە، لە داهاتووشدا نابێت، و لە ئێستاشدا بوونی نییە؛ کەسێک کە بە تەواوی و لە لایەن هەمووانەوە تەنها لۆمە بکرێت، یان بە تەواوی و بێ کەمکوڕی تەنها ستایش بکرێت.",
  "229": "دانایان کاتێک ڕۆژ دوای ڕۆژ تاقیکردنەوە و تێڕامان دەکەن، ستایشی ئەو کەسە دەکەن کە خاوەن ژیانێکی بێگەرد و بێ پەڵەیە، ژیر و هۆشیارە، و خاوەنی زانیاری و فەزیلەتی باڵایە.",
  "230": "کێ دەوێرێت یان دەتوانێت لۆمەی ئەو کەسە بکات کە وەک پارچە زێڕێکی خاوێن کراو و بێگەرد وایە؟ تەنانەت خوداوەندەکانیش ستایشی دەکەن، و لە لایەن خودای باڵاشەوە (برەهما) ستایشی دەکرێت.",
  "231": "پێویستە مرۆڤ خۆی لە کارە چەوتەکانی جەستە بپارێزێت، و جەستەی خۆی لە وێرانکاری کۆنترۆڵ بکات. بە وازهێنان لە ڕەفتارە خراپەکانی جەستە، پێویستە ڕەفتاری جەستەیی خۆی هەمیشە بە پاکی بهێڵێتەوە.",
  "232": "پێویستە مرۆڤ خۆی لە خراپەکارییەکانی زمان و گوتار بپارێزێت، و زمانی خۆی هەمیشە کۆنترۆڵ بکات. بە وازهێنان لە گوتار و قسەی خراپ، پێویستە هەمیشە بە زمانی ڕاست و درست بدوێت.",
  "233": "پێویستە مرۆڤ خۆی لە بیرکردنەوە و نەرێنییەکانی عەقڵ بپارێزێت، و ناخ و هۆشیاریی خۆی کۆنترۆڵ بکات. بە وازهێنان لە بیرکردنەوەی چەوت، پێویستە هەمیشە عەقڵی خۆی لەسەر بیرکردنەوەی ڕاست جێگیر بکات.",
  "234": "دانایان ئەوانەن کە لە کردەوەکانیاندا خۆپارێزن؛ لە گوتار و قسەکانیشیاندا هەمیشە خۆپارێز و بە ئاگان. ئەو دانایانەی کە عەقڵ و ناخی خۆیان کۆنترۆڵ کردووە، بە ڕاستی ئەوانە کەسانی کامڵ و تەواو پارێزراون.",
  "chap18": "پیسییەکان و چڵکەکانی دەروون",
  "235": "ئێستا تۆ ڕێک وەک گەڵایەکی زەرد و ژاکاوی پاییز وایت؛ نێردراوەکانی مەرگ لە بەردەم دەرگاکەتدا ڕاوەستاون و لەسەر لێواری داڕمان و فەوتانی جەستە وەستاویت، کەچی هێشتا هیچ توێشوویەکی ڕۆحیشت بۆ ئەم سەفەرە دوور و نەزانراوە کۆن نەکردووەتەوە.",
  "236": "دوورگەیەک [پەناگەیەک] بۆ خۆت دروست بکە. بە خێرایی تێبکۆشە و ببە بە دانا. کاتێک لە چڵک و پیسییەکان پاک بوویتەوە و چیدی چڵکی ئارەزووت تێدا نەما، دەچیتە ناو کایە ئاسمانییەکەی ئاریاکان [مرۆڤە نەجیبزادە و ڕۆشنبینەکان].",
  "237": "ئێستا ژیانت گەیشتووەتە کۆتایی. بەرەو لای مەرگ بەڕێ کەوتوویت. لەم ڕێگایەشدا هیچ وێستگەیەک نییە بۆ پشوودان، و هیچ توێشوویەکیشت بۆ خۆت دابین نەکردووە.",
  "238": "دوورگەیەک بۆ خۆت دروست بکە. بێ دواکەوتن تێبکۆشە و ببە بە دانا. کاتێک لە چڵک پاک بوویتەوە و بێ ئارەزوو بوویت، چیدی ناگەڕێیتەوە بۆ ناو بازنەی لەدایکبوونەوە و پیری.",
  "239": "مرۆڤی دانا پێویستە پلە بە پلە، کەم کەم، و کات لە دوای کات، پیسی و چڵکەکانی ناخی خۆی داماڵێت، ڕێک وەک چۆن زێڕنگەر یان زیوگەرێک چڵک و خەوشەکانی سەر زیوەکە لادەبات.",
  "240": "وەک چۆن ژەنگ لە ئاسن لە خۆیدا سەرچاوە دەگرێت و کاتێک دروست دەبێت خودی ئاسنەکە دەخوات و لە ناوی دەبات، بە هەمان شێوەش، کردەوەکانی مرۆڤی سەرپێچیکار خۆی پەلکێش دەکەن بەرەو دۆخی نەهامەتی و خەمۆکی.",
  "241": "ئەگەر زانیاری و دەقەکان دووبارە نەکرێنەوە و پێداچوونەوەیان بۆ نەکرێت، لەبیر دەچنەوە و کز دەبن (ئەمە ژەنگی زانیارییە)؛ ئەگەر مرۆڤ تەمبەڵ بێت و تێنەکۆشێت، ژیانی هاوسەری و ناوماڵەکەی بەرەو وێرانبوون دەچێت (ئەمە ژەنگی ماڵە)؛ ئەگەر مرۆڤ گرنگی بە پاکوخاوێنی و ڕەوشت نەدات، جوانییەکەی چڵک هەڵدەگرێت (ئەمە چڵکی سەر جوانییە)؛ و ئەگەر پاسەوانێکیش خەیاڵی بڕوات و بێ ئاگا بێت، دەرگا بۆ مەترسییەکان واڵا دەکات (ئەمە خەوشی گەورەی پاسەوانە).",
  "242": "ڕەفتاری خراپ و ناپاکی، چڵکی ئافرەتە. ڕەزیلی و چاوچنۆکی، چڵکی بەخشەرە. بە ڕاستی، سەرجەم کارە خراپەکان چڵک و پیسین، هەم لەم جیهانەدا و هەم لە جیهانی داهاتووشدا.",
  "243": "بەڵام پیسی و چڵکێک کە لە هەموو ئەمانە خراپتر بێت، نەزانی و جەهلە، کە گەورەترین چڵکی دەروونە. ئەی ڕێبواران (بیکخوەکان)، بە دەستبەرداربوون لەم چڵکە، پاک و بێگەرد بن.",
  "244": "ژیان بۆ مرۆڤی بێ شەرم ئاسانە؛ ئەو کەسەی وەک قەلەڕەش چاو قایم و ڕوودارە، پاشەملە قسە دەکات، خۆسەپێن و لەخۆباییە، و دەروونی گەندەڵ بووە.",
  "245": "بەڵام ژیان دژوار و سەختە بۆ مرۆڤی شەرمن و بە حەیا؛ ئەو کەسەی هەمیشە بەدوای پاکیدا دەگەڕێت، دڵبەستەی شتەکان نییە، بێ فیز و خۆش سروشتە، خاوەن ژیانێکی خاوێنە، و هەمیشە لە تێڕامان و تێڕاماندایە.",
  "246": "هەر کەسێک لەم جیهانەدا ژیانی بوونەرێک لە ناو ببات (بکوژێت)، درۆ بکات، دەست بۆ شتێک ببات کە پێی نەدراوە (بدزێت)، بچێتە لای هاوسەری کەسانی تر (ناپاکی بکات)، و ئاڵوودەی خواردنەوە سەرخۆشکەرەکان بێت،",
  "247": "ئەوا ئەو کەسە لەم جیهانەدا خەریکە بە دەستی خۆی ڕەگ و ڕیشەی خۆی هەڵدەکەنێت.",
  "248": "ئەی مرۆڤی چاک، بەم شێوەیە بزانە: 'کۆنترۆڵکردنی شتە خراپەکان کارێکی ئاسان نییە.' ڕێگا مەدە تەماحکارانە و بەدکاری، تۆ پەلکێشی ناو مەینەتی و عەزابێکی درێژخایەن بکەن.",
  "249": "خەڵکی بەپێی باوەڕ و ڕادەی ڕازیبوونی ناخی خۆیان دەبەخشن. هەر کەسێک لە نێوانیاندا حەسودی و ئیرەیی بە خواردن و خواردنەوەی کەسانی تر ببات، نە لە ڕۆژدا و نە لە شەودا ناگات بە چرکەیەک ئارامی.",
  "250": "بەڵام ئەو کەسەی کە ئەم هەستەی [ئیرەیی] بە تەواوی بڕیوە، ڕیشەکێشی کردووە و لە ناوی بردووە، ئەوا هەم لە ڕۆژ و هەم لە شەودا دەگات بە ئارامیی ڕەها.",
  "251": "هیچ ئاگرێک وەک ئاگری شەهوەت نییە، هیچ تەڵە و گرتنێک وەک کینە نییە، هیچ داو و تۆرێک وەک وەهم و سەرلێشێواوی نییە، و هیچ ڕووبارێکیش وەک ڕووباری تەماح و تینووێتیی دەروون (تانها) خڕۆشاو نییە.",
  "252": "بینینی خەوش و هەڵەی کەسانی تر زۆر ئاسانە، بەڵام بینینی خەوشەکانی خۆت یەکجار دژوارە. مرۆڤ هەڵەی کەسانی تر وەک کای پێش با دەدات و بڵاوی دەکاتەوە، بەڵام هەڵەکانی خۆی دەشارێتەوە، ڕێک وەک ڕاوچییەکی فێڵباز کە خۆی لە پشت ئەو تەپوتۆز و کایەوە حەشار دەدات.",
  "253": "ئەو کەسەی تەنها خەوشی کەسانی تر دەبینێت و هەمیشە خێرا توڕە و توند دەبێت، گەندەڵی و چڵکەکانی ناخی زیاتر گەشە دەکەن. ئەو کەسە یەکجار دوورە لە تێکشکاندن و لە ناوبردنی چڵکەکانی دەروون.",
  "254": "لە ئاسماندا هیچ شوێنپێ و ڕێچکەیەک نییە. لە دەرەوەی [ڕێگای ڕزگاریی ناوەکیدا] هیچ پیرۆز و سۆفییەک بوونی نییە. مرۆڤایەتی چێژ لە کۆسپ و بەربەستەکان دەبینێت [مەبەست لەو کۆسپانەیە کە عەقڵ دروستیان دەکات]، بەڵام تاتهاگاتاکان [ئەوانەی گەیشتوونەتە حەقیقەت/بووداکان] لە سەرجەم کۆسپ و بەربەستەکان ئازادن.",
  "255": "لە ئاسماندا هیچ شوێنپێ و ڕێچکەیەک نییە. لە دەرەوەدا هیچ پیرۆزێک بوونی نییە. هیچ شتێکی مەرجدار و دروستکراو نییە کە هەمیشەیی و ئەبەدی بێت. هیچ جۆرە ناسەقامگیری و لادانێکیش لە ناخی بووداکاندا بوونی نییە.",
  "chap19": "دادپەروەری و سەرڕاستی",
  "256": "مرۆڤ بەوە نابێتە دادپەروەر کە بە پەلەپەلی بێسەروبەر و بێ وردبوونەوە بڕیار لەسەر کێشەکان بدات. دانای ڕاستەقینە ئەو کەسەیە کە بە باشی لێکۆڵینەوە لە هەردوو لایەنی ڕاست و چەوت دەکات.",
  "257": "ئەو مرۆڤە هۆشیارەی کە خەڵکی بە چەواشەکاری و نادادپەروەری ڕێبەری ناکات، بەڵکوو بەپێی یاسای حەقیقەت و بێ لایەنانە هاوسەنگی دەپارێزێت؛ ئەو کەسەی کە پاسەوانی دیسپلین و ڕاستییە، بە شایستەیی پێی دەگوترێت 'سەرڕاست و پەیڕەوکاری یاسای حەقیقەت'.",
  "258": "مرۆڤ تەنها بەوە نابێتە زانا و خاوەن مەعریفە کە زۆر قسە بکات. ئەو کەسەی کە لە ناخیدا سەقامگیر و پارێزراوە، کینەی تێدا نییە، و لە ترس ڕزگاری بووە؛ پێی دەگوترێت [زانا].",
  "259": "مرۆڤ تەنها بە زۆر گوتن نابێتە شارەزا لە یاسای حەقیقەت (دەهاما). بەڵکوو ئەو کەسەی کە تەنانەت ئەگەر کەمیشی بیستبێت، بەڵام حەقیقەت بە چاوی ناخ و عەقڵی دەبینێت و فەرامۆشی ناکات، ئەوا ئەو کەسە بە ڕاستی شارەزای حەقیقەتە.",
  "260": "مرۆڤ تەنها بەوە نابێتە پێشەوا و پیرێکی خاوەن شکۆ (تێرا) کە قژی سپی بووبێت. ئەو تەنها تەمەنی تێپەڕیوە و پێی دەگوترێت [بە خۆڕایی-پیربوو].",
  "261": "بەڵام ئەو کەسەی کە ڕاستگۆیی، فەزیلەت، بێ ئازاری، خۆپارێزی و کۆنترۆڵی نەفسی تێدایە؛ ئەو دانایەی کە لە چڵک و پیسییەکان پاک بووەتەوە، بە ڕاستی پێی دەگوترێت پێشەوا و پیرێکی خاوەن شکۆ.",
  "262": "مرۆڤ بە زمان خۆشی و قسەی خۆش، یان بە ڕوخسارێکی جوان و سەرنجڕاکێش نابێتە خاوەن سروشتێکی چاک، ئەگەر لە ناخیدا حەسود، خۆپەرست و فێڵباز بێت.",
  "263": "بەڵام ئەو کەسەی کە ئەم خەسڵەتە نەرێنییانە لە ناخیدا بە تەواوی بڕاون، ڕیشەکێش کراون و تواونەتەوە؛ ئەو دانایەی کە لە کینە و ڕق پاک بووەتەوە، بە ڕاستی پێی دەگوترێت خاوەن سروشتێکی چاک.",
  "264": "مرۆڤی بێ دیسپلین کە درۆ دەکات، تەنها بە تاشینی قژی نابێتە ڕێبواری حەقیقەت. کەسێک کە پڕ بێت لە تەماح و چاوچنۆکی، چۆن دەبێتە ڕێبوار؟",
  "265": "ئەو کەسەی کە بە تەواوی زاڵ دەبێت بەسەر کردەوە خراپەکاندا، چ گەورە بن یان بچووک؛ پێی دەگوترێت ڕێبوار، چونکە بەسەر تەواوی بەدکارییەکاندا سەرکەوتووە.",
  "266": "مرۆڤ تەنها بەوە نابێتە ڕێبواری ڕاستەقینە (بیکخو) کە سواڵ لە خەڵکی بکات؛ بەڵکوو بە پەیڕەوکردنی تەواوی کۆدی ڕەوشت و یاسای حەقیقەت دەبێتە ڕێبوار، نەک تەنها بەو جۆرە پارە و خۆراک کۆکردنەوەیە.",
  "267": "لێرەدا، ئەو کەسەی کە لە هەردوو چەمکی [مادیی] چاکە و خراپە باڵاتر بووەتەوە، ڕەفتاری بەرز و پیرۆزە، و بە تێگەیشتن و هۆشیارییەوە لەم جیهانەدا دەژی؛ بە ڕاستی تەنها بەو دەگوترێت ڕێبوار (بیکخو).",
  "268": "مرۆڤی کڵۆڵ و نەزان تەنها بە بێدەنگبوون نابێتە دانا و حەکیم؛ بەڵکوو ئەو دانایەی کە وەک بڵێی تەرازوویەکی بە دەستەوە بێت، باشترینی نێو شتەکان هەڵدەبژێرێت و لە خراپە دوور دەکەوێتەوە، بە ڕاستی ئەو دانایە.",
  "269": "هەر بەم هۆیەشەوەیە کە ئەو دانایە. ئەو کەسەی کە لە هەردوو جیهانی [ناوەکی و دەرەکی] تێدەگات، لەبەر ئەوە پێی دەگوترێت دانا.",
  "270": "مرۆڤ بە ئازاردانی بوونەوەرە زیندووەکان نابێتە نەجیبزادە و ڕۆشنبین (ئاریا)؛ بەڵکوو بەهۆی بێ ئازاری و نەبوونی توندوتیژییەوە بەرامبەر بە سەرجەم بوونەوەرە زیندووەکان، پێی دەگوترێت نەجیبزادە.",
  "271": "ئەی ڕێبوار (بیکخو)، تەنها بە ڕەوشت بەرزی و تاقیکردنەوەی سەختی دەروونی، یان بە خوێندنەوە و زانیاری زۆر، یان تەنانەت بە پەرەپێدانی خەستیی عەقڵ (تێڕامان)، و مانەوە لە شوێنی گۆشەگیر و تەنیادا، مەبە بە کەمتیار و مەڵێ 'من چێژ لە بەختەوەریی دەستبەرداربوون دەبینم کە خەڵکی ئاسایی دەستیان پێی ناگات'؛",
  "272": "تا ئەو کاتەی نەگەیشتوویتەتە قۆناغی کوژانەوەی تەواوی چڵک و پیسییەکانی دەروون، متمانە بەم دۆخانە مەکە و تێیدا ڕامەوەستە.",
  "chap20": "ڕێگا",
  "273": "باشترینی ڕێگاکان، ڕێگای هەشت خەسڵەتییە، باشترینی حەقیقەتەکان، چوار وتە بەرزەکەیە (چوار حەقیقەتە پیرۆزەکە). باشترینی دۆخەکان، دۆخی دڵنەبەستنە - باشترینی بوونەوەرە دوو پێیەکانیش، ئەو زاتەیە کە خاوەن بینینی حەقیقەتە (بوودا).",
  "274": "ئەمە تەنها ڕێگایە؛ هیچ ڕێگایەکی تر نییە بۆ پاککردنەوەی بینین و تێگەیشتن. پەیڕەوی لەم ڕێگایە بکەن؛ چونکە ئەم ڕێگایە دەبێتە هۆی سەرلێشێوان و تێکشکانی مارا [شەیتان].",
  "275": "ئەگەر بەم ڕێگایەدا هەنگاو بنێیت، کۆتایی بە سەرجەم ئازار و مەینەتییەکانی ناخت دەهێنیت. من ئەم ڕێگایەم بۆ واڵا کردوون، دوای ئەوەی خۆم لە ڕێگەی دۆزینەوەی حەقیقەتەوە، فێری چۆنییەتی دەرھێنانی دڕکی ژان و وەهم بووم.",
  "276": "پێویستە هەوڵدان و تێکۆشان لە لایەن خۆتانەوە بێت؛ تاتهاگاتاکان [بووداکان] تەنها مامۆستا و ڕێپیشاندەرن. ئەو کەسانەی خەریکی تێڕامان دەبن و دەچنە ناو ئەم ڕێگایەوە، لە کۆت و بەندەکانی مارا ڕزگاریان دەبێت.",
  "277": "سەرجەم شتە مەرجدار و دروستکراوەکان کاتین و لە ناو دەچن؛ کاتێک مرۆڤ بە چاوی داناییەوە درک بەمە دەکات، ئەوا لە ئێش و خەمباری بێزار دەبێت و لێی جیا دەبێتەوە؛ ئەمەیە ڕێگای گەیشتن بە پاکی.",
  "278": "سەرجەم شتە مەرجدار و دروستکراوەکان پڕن لە ئێش و ناسۆری؛ کاتێک مرۆڤ بە چاوی داناییەوە درک بەمە دەکات، ئەوا لە ئێش و خەمباری بێزار دەبێت؛ ئەمەیە ڕێگای گەیشتن بە پاکی.",
  "279": "سەرجەم دیاردە و یاساکان، بێ جەوهەر و بێ ناسنامەی سەربەخۆین؛ کاتێک مرۆڤ بە چاوی داناییەوە درک بەم ڕاستییە دەکات، ئەوا لە کایەی ئێش و ناسۆری دادەبڕێت و تێیدا نامێنێتەوە؛ ئەمەیە ڕێچکەی گەیشتن بە پاکی و ڕزگاریی ڕەها.",
  "280": "ئەو تەمبەڵە بێکارەی کاتێک پێویستە تێبکۆشێت کەچی هەوڵ نادات، سەرەڕای ئەوەی گەنج و بەهێزیشە بەڵام سستە، و بیرکردنەوەکانی داڕوخاون؛ هەرگیز لە ڕێگەی داناییەوە ناگات بە درککردنی ڕێگای حەقیقەت.",
  "281": "با مرۆڤ چاودێری قسەکانی بێت، عەقڵی بە باشی کۆنترۆڵ بکات، و لە ڕێگەی جەستەیەوە چاکە نەبێت هیچ کارێکی ناڕێک نەکات. با ئەم سێ ڕێگایەی کردەوە [قسە، عەقڵ، جەستە] پاک بکاتەوە و بگات بەو ڕێگایەی کە حەکیمەکان دۆزیویانەتەوە.",
  "282": "بە ڕاستی، لە تێڕامان و قووڵبوونەوەوە دانایی سەرچاوە دەگرێت؛ بەبێ تێڕامانیش دانایی کز دەبێت و لە ناو دەچێت. بە ناسینی ئەم دوو ڕێگایەی قازانج و زیان [گەشە و کزبوون]، با مرۆڤ ژیانی خۆی بە شێوازێک ئاڕاستە بکات کە داناییەکەی ڕووی لە زیادبوون بێت.",
  "283": "دارستانی [ئارەزووەکان] ببڕنەوە، نەک دارە ڕاستەقینەکان. چونکە لە دارستانی [ئارەزووەکانەوە] ترس سەرچاوە دەگرێت. ئەی ڕێبواران [بیکخوەکان]، بە بڕینەوەی دارستان و دەوەنەکانی ناو ناخ، خۆتان لەم دارستانە ڕزگار بکەن.",
  "284": "تا ئەو کاتەی بچووکترین دەوەنی [ئارەزووی] پیاو بەرامبەر بە ئافرەت نەبڕدرێتەوە، هێشتا عەقڵی لە کۆت و بەنددایە، ڕێک وەک گوێرەکەیەکی شیرەخۆر کە بە دوای مانگا دایکیدا وێڵە.",
  "285": "دڵبەستەیی و حەزەکانی ناخت ببڕەوە، ڕێک وەک چۆن بە دەست، گوڵە کێوییەکی پاییزانە دەپچڕێنیت. تەنها پەرە بە ڕێگای ئاشتیی ناوەکی بدە. نیببانای ڕاستەقینە لە لایەن زاتی پیرۆزەوە [بوودا] ڕوون کراوەتەوە.",
  "286": "'لێرەدا لە وەرزی باراندا دەژیم، لێرەش لە پاییز و هاویندا'، مرۆڤی نەفام بەم شێوازە بۆ داهاتوو پلان دادەنێت و خەیاڵ دەکات، کاتێک لە مەترسیی کتوپڕی مەرگ بێ ئاگایە.",
  "287": "ئەو مرۆڤە شەیدایەی کە عەقڵی تەنها لای منداڵ و سەروەت و سامانەکەیەتی، مەرگ دێت و پەلکێشی دەکات و دەیبات؛ ڕێک وەک لافاوێکی گەورە کە دێ دێیەکی نوستوو ڕادەماڵێت.",
  "288": "هیچ کچ و کوڕێک نین بۆ پاراستنی مرۆڤ لە چرکەساتی مەرگدا، نە باوک و نە دۆست و هاوڕێ؛ بۆ ئەو کەسەی کە مەرگ بەسەریدا زاڵ بووە، هیچ پاراستنێک لە لایەن خزمانەوە بەدی ناکرێت.",
  "289": "بە درککردن بەم ڕاستییە، با مرۆڤی بەڕەوشت و دانا، بە خێرایی ئەو ڕێگایە پاک بکاتەوە کە بەرەو نیببانا [ڕزگاریی ڕەها] دەچێت.",
  "chap21": "بابەتی جۆراوجۆر",
  "290": "ئەگەر مرۆڤ بە دەستبەرداربوون لە خۆشی و بەختەوەرییەکی کەم، بگات بە بینین و چەشتنی بەختەوەرییەکی مەزنتر؛ با مرۆڤی دانا لە پێناو ئەو بەختەوەرییە مەزنترەدا، دەستبەرداری خۆشییە کەمەکە بێت.",
  "291": "ئەو کەسەی کە دەیەوێت بەختەوەریی خۆی لە ڕێگەی ئازاردانی کەسانی ترەوە بەدەست بهێنێت، خۆی لە داوی کینە و ڕقدا تێوەدەگلێنێت و هەرگیز لەو کۆتوبەندە ڕزگاری نابێت.",
  "292": "ئەوەی پێویست بوو بکرێت پشتگوێ خراوە، و ئەوەی نەدەبوو بکرێت ئەنجام دراوە. بۆ ئەو کەسانەی کە لوتبەرز و غافڵن، چڵک و پیسییەکانی دەروون ڕوو لە زیادبوون دەکەن.",
  "293": "ئەو کەسانەی کە هەمیشە بە دڵسۆزییەوە پەیڕەوی لە [هۆشیاریی جەستە] دەکەن، کارێک ناکەن کە نەشیاو بێت، و بەردەوام سەرگەرمی ئەو کارانەن کە پێویستە بکرێن؛ پیسییەکانی دەروونی ئەم کەسە هۆشیار و تێڕامانکارانە کۆتایی پێ دێت.",
  "294": "بە کوشتنی دایک [تەماح و ئارەزوو] و باوک [لوتبەرزی و فیز]، و لەناوبردنی دوو پاشای جەنگاوەر [دیدگاکانی ئەزەلگەرایی و پووچگەرایی]، و بە وێرانکردنی نیشتمانێک [دەروازەکانی هەست و بابەتە هەستییەکان] لەگەڵ ئەفسەری باجەکەیدا [دڵبەستەیی، پەیوەستبوون]؛ براھما [ئاراھانت - گەیشتوو بە ڕزگاری] بەبێ خەمباری ڕێ دەکات.",
  "295": "ئەو ڕێبوارە بەدیهاتوو و گەیشتووەی [براھما] کە توانیویەتی ئارەزووی کاتی [دایک] و لوتبەرزیی ناخی [باوک] لە ناو ببات، و بەسەر دیدگا چەوتەکانی جیهانبیندیدا [دوو پاشاکە] سەرکەوێت، و سەرجەم کۆسپ و تەگەرەکانی سەر عەقڵی [ڕێگا مەترسیدارەکە] ڕیشەکێش بکات؛ بەبێ هیچ غەمباری و خەمۆکییەک لەم جیهانەدا ڕێ دەکات و دەگاتە ئارامیی ڕەها.",
  "296": "قوتابییەکانی گۆتاما [بوودا] هەمیشە بە هۆشیارییەکی باڵاوە ڕادەپەڕن؛ ئەوانەی کە شەو و ڕۆژ بەردەوام تێڕامان لەسەر بوودا دەکەن.",
  "297": "قوتابییەکانی گۆتاما هەمیشە بە هۆشیارییەکی باڵاوە ڕادەپەڕن؛ ئەوانەی کە شەو و ڕۆژ بەردەوام تێڕامان لەسەر دەهاما [یاسای حەقیقەت] دەکەن.",
  "298": "قوتابییەکانی گۆتاما هەمیشە بە هۆشیارییەکی باڵاوە ڕادەپەڕن؛ ئەوانەی کە شەو و ڕۆژ بەردەوام تێڕامان لەسەر سانگها [کۆمەڵگەی ڕێبواران] دەکەن.",
  "299": "قوتابییەکانی گۆتاما هەمیشە بە هۆشیارییەکی باڵاوە ڕادەپەڕن؛ ئەوانەی کە شەو و ڕۆژ بەردەوام تێڕامان لەسەر سروشتی جەستە دەکەن.",
  "300": "قوتابییەکانی گۆتاما هەمیشە بە هۆشیارییەکی باڵاوە ڕادەپەڕن؛ ئەوانەی کە شەو و ڕۆژ چێژ لە بێ ئازاری و نەبوونی توندوتیژی دەبینن.",
  "301": "قوتابییەکانی گۆتاما هەمیشە بە هۆشیارییەکی باڵاوە ڕادەپەڕن؛ ئەوانەی کە شەو و ڕۆژ چێژ لە تێڕامان و قووڵبوونەوەی دەروونی دەبینن.",
  "302": "دەستبەرداربوون [لە جیهانی مادی] سەختە، و چێژبینین لێی هێندەی تر سەختە. ژیانی ناوماڵ و خێزانییش پڕە لە ئێش و دژواری. هاودەمبوون لەگەڵ کەسانی نەگونجاویش ناسۆرییە. ڕێبواری گەڕۆکیش [لە خولی هەمیشەیی لە دایکبوونەوەدا - سامسارا] دووچاری نەهامەتی دەبێت؛ بۆیە مەبە بەو ڕێبوارە و شوێن چەرمەسەری مەکەوە.",
  "303": "ئەو کەسەی کە پڕە لە متمانە و فەزیلەت، و خاوەنی ناوبانگی چاک و سامانی ڕۆحییە، لە هەر شوێنێک بێت و بۆ هەر زەوییەک کۆچ بکات، لەوێ ڕێزی لێ دەگیرێت.",
  "304": "مرۆڤە چاکەکان تەنانەت لە دووریشەوە وەک چیای هیمالایا خۆیان دەردەخەن و دەبینرێن؛ بەڵام مرۆڤە بەدکارەکان، تەنانەت ئەگەر نزیکیش بن، نادیارن ڕێک وەک ئەو تیرانەی کە لە تاریکیی شەودا دەهاوێژرێن.",
  "305": "ئەو کەسەی بە تەنیا دادەنیشێت، بە تەنیا پشوو دەدات، بە تەنیا و بێ تەمبەڵی ڕێ دەکات، و لە تەنیاییدا عەقڵی خۆی کۆنترۆڵ دەکات، ئەوا لە قووڵایی دارستاندا چێژ و ئارامیی ڕاستەقینە دەدۆزێتەوە.",
  "chap22": "دۆخی پڕ لە ژان",
  "306": "ئەو کەسەی درۆ دەکات دەچێتە ناو دۆخێکی پڕ لە ژان و سەرگەردانییەوە؛ هەروەها ئەو کەسەش کە کارێکی کردووە و پاشان دەڵێت 'من نەمکردووە'. هەردووکیان دوای مردن لە جیهانەکەی تردا یەکسان دەبن؛ چونکە مرۆڤی خاوەن کردەوەی نزم و سووکن.",
  "307": "زۆرن ئەوانەی پۆشاکی زەردی ڕێبوارانیان پۆشیوە، بەڵام خاوەن سروشتێکی بەد و بێ دیسپلینن. ئەم بەدکارانە بەهۆی کردەوە خراپەکانیانەوە، لە دۆخێکی پڕ لە ژان و سزادا لە دایک دەبنەوە.",
  "308": "بۆ مرۆڤێکی بێ ڕەوشت و بێ دیسپلین، زۆر چاکترە گۆشەیەکی ئاسنی سووربووەوە وەک بڵێسەی ئاگر قووت بدات [کە ناخی بسووتێنێت]، نەک بەو حاڵەوە بچێت ئەو خۆراک و خێرە بخوات کە خەڵکی نەدار بە دڵپاکی پێشکەشی دەکەن.",
  "309": "چوار بەدبەختی و نەهامەتی بەسەر ئەو مرۆڤە غافڵەدا دێت کە داوێنپیسی [زینا] دەکات: یەکەم؛ کۆکردنەوەی کارمای خراپ و گوناھـ، دووەم؛ شڵەژان و تێکچوونی خەو، سێیەم؛ تانە و پلە و سەرکۆنەی خەڵکی، و چوارەم؛ کەوتنە ناو دۆخێکی پڕ لە ژان و دۆزەخی.",
  "310": "لەم کارەدا هەم کارمای خراپ هەیە و هەم چارەنووسێکی شوم. چێژ و خۆشیی ئەو ژن و پیاوە ترساوە زۆر کورتخایەنە، و یاسای پادشاش سزایەکی قورس دەسەپێنێت. کەواتە با هیچ پیاوێک نزیکی هاوسەری کەسی تر نەکەوێت.",
  "311": "ڕێک وەک چۆن 'گیای کوسا' ئەگەر بە شێوازێکی هەڵە و شل دەستی پێدا بگریت، دەستت دەبڕێت؛ بە هەمان شێوە، ڕێبواری و ژیانی ڕەبەنیش ئەگەر بە چەوتی پەیڕەو بکرێت، مرۆڤ کێش دەکات بەرەو دۆخێکی پڕ لە ژان.",
  "312": "هەر کردەوەیەکی بێسەروبەر، هەر ڕەفتارێکی گەندەڵانە، و ژیانێک کە تێیدا پیرۆزی و پاکی کەم و کوڕ و جێی گومان بێت؛ هیچ کام لەمانە بەرهەم و قازانجێکی مەزنیان نابێت.",
  "313": "ئەگەر پێویستە کارێک ئەنجام بدرێت، با مرۆڤ بە تەواوی بیکات. با بە شێوازێکی جێگیر و پتەو پەرەی پێ بدات؛ چونکە تێکۆشانی شل و سست، تەنها تەپوتۆزی وەهم و ئارەزووەکان لە ناخدا زیاتر بڵاو دەکاتەوە.",
  "314": "نەکردنی کردەوەی خراپ زۆر چاکترە؛ چونکە گوناھـ و بەدکاری لە پاشاندا مرۆڤ ئەشکەنجە دەدات. لە بەرامبەردا، ئەنجامدانی کردەوەی چاک زۆر باشترە، چونکە دوای کردنی، مرۆڤ دووچاری پەشیمانی و خەمباری نابێتەوە.",
  "315": "وەک چۆن شارێکی سەر سنوور، لە ناوەوە و دەرەوەیدا پاسەوانی لێ دەکرێت، تۆش بەو شێوەیە پاسەوانی لە ناخی خۆت بکە. مەهێڵە ئەم دەرفەتەی [ژیانی هۆشیاری] لە دەستت بچێت؛ چونکە ئەوانەی دەرفەتەکە بەفیڕۆ دەدەن، کاتێک لە دۆخی پڕ لە ژان و سەرگەردانیدا لە دایک دەبنەوە، تەنها خەم دەخۆن.",
  "316": "ئەو بوونەوەرانەی کە شەرم دەکەن لەوەی شایستەی شەرمەزاری نییە [وەک کردەوەی پاک]، و شەرمیش ناکەن لەوەی کە بە ڕاستی جێگەی شەرمەزارییە؛ باوەش بۆ دیدگای چەوت دەگرنەوە و بەرەو دۆخێکی پڕ لە ژان دەچن.",
  "317": "ئەو بوونەوەرانەی ترس لەو شتانەدا دەبینن کە ترسی ناوێت، و هیچ ترسێکیش لەو شتانەدا نابینن کە بە ڕاستی مەترسیدار و تۆقێنەرن [وەک کارمای خراپ]؛ پەیڕەوی لە دیدگای ناڕاست دەکەن و بەرەو دۆخێکی پڕ لە ژان دەچن.",
  "318": "ئەو بوونەوەرانەی کە عەیب و خەوش لە شتی بێ خەوشدا دەبیننەوە، و هیچ کەمکوڕییەکیش لە کاری چەوت و هەڵەدا نابینن؛ دەست دەدەنە دیدگای فێڵاویی و بەرەو دۆخێکی پڕ لە ژان دەچن.",
  "319": "بەڵام ئەو بوونەوەرانەی کە چەوتی وەک چەوتی دەناسن و ڕاستیش وەک ڕاستی دەبینن؛ باوەش بۆ دیدگای دروست و حەقیقەت دەگرنەوە و بەرەو دۆخێکی باڵا و پڕ لە بەختەوەریی ڕاستەقینە [بڵیس] بەڕێ دەکەون.",
  "chap23": "فیل",
  "320": "وەک چۆن فیلێکی جەنگاوەر لە مەیدانی نەبەردیدا لە بەرامبەر ئەو تیرانەی لە کەوانەوە دەهاوێژرێن خۆڕاگرە، منیش بەو شێوەیە بەرگەی تانە و تەشەر و قسەی ناخۆش دەگرم؛ چونکە بە ڕاستی زۆربەی خەڵکی، بێ دیسپلین و ناهۆشیارن.",
  "321": "[ئەسپ یان فیلی] ڕاهێنراو دەبەنە ناو کۆڕ و کۆبوونەوەکانەوە. پادشا تەنها سواری ئاژەڵی ڕاهێنراو دەبێت. لە نێوان مرۆڤەکانیشدا، باشترینیان ئەو کەسە ڕاهێنراو و خاوەن دیسپلینەیە کە بەرگەی تانە و تەشەر دەگرێت [و هێمنیی ناخی تێکناچێت].",
  "322": "هێسترە ڕاهێنراوەکان نایابن، ئەسپە ڕەسەنەکانی ناوچەی 'سیندھـ' و فیلە گەورە خاوەن ددانە درێژەکانیش هێندە بەڕێزن؛ بەڵام لە هەموو ئەمانە بەرزتر و باشتر، ئەو مرۆڤەیە کە ناخی خۆی ڕاهێناوە و کۆنترۆڵی کردووە.",
  "323": "بە دڵنیاییەوە مرۆڤ بەو هۆکار و ئامرازانەی گواستنەوە [ئەسپ و فیل] هەرگیز ناتوانێت بچێتە ناو ئەو زەمینە پێ تێ نەخراوەی نیببانا، بەو شێوەیەی کە کەسی خۆکۆنترۆڵکەر لە ڕێگەی ناخە ڕاهێنراوو ڕامکراوەکەیەوە پێی دەگات.",
  "324": "فیلە دداندرێژە دیل و سەرکێشەکە کە ناوی 'دھانەپاالکا'یە، کاتێک لە کاتی مەستیدا شیلەی توند لە گۆناکانیدا دەقوڵپێت، تەنانەت یەک پارووش ناخوات؛ چونکە ئەو فیلە تەنها بیری لای دارستانی فیلەکان و ئازادییە.",
  "325": "مرۆڤی گەمژە کاتێک تەمبەڵ و سست دەبێت، چاوچنۆک و چڵێس دەبێت، و هەمیشە خەواڵووە؛ ڕێک وەک بەرازێکی گەورە کە بە پاشماوەی خۆراک قەڵەو کرابێت بەملا و بەولادا دەگەڕێتەوە، ئەو کەسە چەندین جار و بەردەوام لە خولی ئازاردا [لە دایکبوونەوە] دەخولێتەوە.",
  "326": "لە ڕابردوودا، ئەم عەقڵە بۆ هەرکوێ کەیفی لێ بووایە، بەپێی حەز و ئارەزووەکانی خۆی سەرگەردان دەبوو. بەڵام دڵنیابن ئەمڕۆ بە هۆشیاری و سەرنجێکی قووڵەوە بە تەواوی ڕێگری لێ دەکەم و دەستەمۆی دەکەم، ڕێک وەک چۆن بەخێوکەری فیل کۆنترۆڵی فیلێکی سەرکێش و مەست دەکات.",
  "327": "چێژ لە هۆشیاری و وریا بوون ببینن. پاسەوانی لە عەقڵی خۆتان بە باشی بکەن. خۆتان لە ڕێگای بەدکاری و گەندەڵی دەربهێنن، ڕێک وەک ئەو فیلە بەهێزەی کە خۆی لە ناو زۆنگاو و قوڕاوێکی قووڵ دەکێشێتە دەرەوە.",
  "328": "ئەگەر هاوەڵێکی ژیر و وریات دەستکەوت کە شایستەی هاوژینی بێت، ڕەفتاری چاک بێت و خاوەن دانایی بێت، ئەوا پێویستە بە شادی و هۆشیارییەوە لەگەڵیدا بژیت و پێکەوە بەسەر سەرجەم مەترسییەکاندا سەربکەون.",
  "329": "بەڵام ئەگەر هاوەڵێکی ژیر و وریات دەستنەکەوت کە شایستەی هاوژینی بێت، و ڕەفتاری چاک و دانا بێت؛ ئەوا وەک پادشایەک کە واز لە شانشینە داگیرکراوەکەی دەهێنێت [و دەچێتە تەنیاییەوە]، بە تەنیا بژی، ڕێک وەک فیلێک کە بە تەنیا لە دارستانی فیلەکاندا دەگەڕێت.",
  "330": "ژیان لە تەنیاییدا زۆر چاکترە؛ چونکە چوونە پاڵ مرۆڤی نەزان و غافڵ هیچ دۆستایەتی و بەرهەمێکی تێدا نییە. با مرۆڤ بە تەنیا بژیت و هیچ بەدکارییەک نەکات، بێخەم و بێ بەستراوەیی بێت، ڕێک وەک فیلێک لە قووڵایی دارستاندا.",
  "331": "لە کاتی پێویستیدا، بوونی هاوڕێیان چێژبەخشە. ڕازیبوون و قەناعەتکردن بەوەی لە بەردەستدایە [چ کەم بێت یان زۆر] چێژبەخشە. کاتێک ژیانیش بەرەو کۆتایی دەچێت، خاوەندارێتی لە کارمای چاک و فەزیلەت ئارامی بەخشە. دوورکەوتنەوە لە سەرجەم ئێش و ناسۆرییەکانیش بەرزترین چێژە.",
  "332": "لەم جیهانەدا، خزمەتکردن و بەدەمەوەچوونی دایک مایەی بەختەوەرییە. خزمەتکردنی باوکیش بە هەمان شێوە مایەی بەختەوەری و چێژە. ڕێزگرتن و هاوکاریکردنی ڕێبوارانی حەقیقەت [ئەسکیتیس] شتێکی شیرینە، و خزمەتکردنی ئەوانەش کە گەیشتوونەتە پلەی نەجیبزادەیی و ڕۆشنبینی بەرزترین شادومانییە.",
  "333": "پاراستنی فەزیلەت و پاکی ناخ تا تەمەنی پیری، چێژبەخش و جوانە. بوونی متمانە و باوەڕێکی جێگیر و نەهەژاو ئارام بەخشە. بە دەستهێنانی دانایی ڕاستەقینە مایەی خۆشییە، و ئەنجامنەدانی چەوتی و بەدکاری، گەورەترین ئاسوودەیییە.",
  "chap24": "تینوێتی و حەز",
  "334": "حەز و ویستی ئەو کەسەی خوی داوەتە ژیانێکی غافڵ و بێ دیسپلین، ڕێک وەک دەوەنێکی کێوی و لولخواردوو گەشە دەکات. ئەو لە ژیانێکەوە بۆ ژیانێکی تر باز دەدات، ڕێک وەک مەیموونی دارستان کە بەدوای میوەدا لە لقێکەوە بۆ لقێکی تر باڵەکووتێ دەکات.",
  "335": "لەم جیهانەدا، هەر کەسێک کە بەسەر ئەم تینوێتییە نزم و خۆ پێوەنووسێنەرەدا زاڵ نەبێت، خەم و ناسۆرەکانی لە ناخیدا پەرە دەسێنن، ڕێک وەک گیای بیرەنا، کاتێک ئاوی باشی پێ بگات چۆن تەشەنە دەکات.",
  "336": "بەڵام هەر کەسێک لەم جیهانەدا بەسەر ئەم حەزە نزم و سەرکێشەدا سەرکەوێت، خەم و پەژارەکان لە ناخی دەوەرن، ڕێک وەک دڵۆپە ئاوەکان کاتێک لەسەر گەڵای گوڵە نیلۆفەرێک دەخلیسکێن و لێی دەبنەوە.",
  "337": "من ئەمەتان پێ دەڵێم: هیوای بەختێکی باش بۆ هەموو ئەو کەسانەی لێرە کۆبوونەتەوە! ڕەگی ئەم حەزە نزمە هەڵکەنن، ڕێک وەک چۆن کەسێک زەوی هەڵدەکەنێت بۆ دۆزینەوەی ڕەگە شیرینەکەی گیای بیرەنا. مەهێڵن مارا [شەیتان] چەندین جار و بەردەوام بتانهاڕێت، وەک چۆن لافاوێک قامیشێک وردوخاش دەکات.",
  "338": "ڕێک وەک چۆن دارێک ئەگەر ڕەگەکانی بێوەی و قایم بمێننەوە، تەنانەت ئەگەر لق و پۆپیشی ببڕدرێتەوە، دووبارە چرۆ دەکاتەوە؛ بە هەمان شێوە، تا ئەو کاتەی حەزە شاراوەکان لە ناخدا ڕیشەکێش نەکرێن، ئەم ئێش و ناسۆرییە چەندین جار و بەردەوام سەر هەڵدەداتەوە.",
  "339": "ئەگەر لە ناخی هەر کەسێکدا، ئەو ٣٦ جۆگەیەی [حەز و تەماح] کە بەرەو بیرکردنەوە چێژبەخشەکان دەڕۆن بەهێز بن، ئەوا لافاوی بیرکردنەوە ملهوڕەکانی شەهوەت و ئارەزوو، ئەو مرۆڤە سەرلێشێواوە لەگەڵ خۆیاندا ڕادەماڵن و دەیبەن.",
  "340": "جۆگەکانی [حەز] بۆ هەموو شوێنێک دەقوڵپێن. دەوەنی لولخواردووی [تەماح] چرۆ دەکات و ڕادەوەستێت. کاتێک دەبینیت ئەم دەوەنە لە ناختدا سەر دەر دەکات، بە شمشێری دانایی ڕەگەکەی ببڕەوە.",
  "341": "لە ناخی بوونەوەرەکاندا چێژگەلێک سەر هەڵدەدەن کە بەرەو بابەتە هەستییەکان پەل دەهاوێن، و [ئەم بوونەوەرانە] لە قووڵایی حەزدا نوقم دەبن. ئەوان تەنها خەریکی ڕاوکردنی خۆشین و بەدوای بەختەوەریی کاتیدا وێڵن. بە ڕاستی، ئەم جۆرە مرۆڤانە هەمیشە دەچنەوە ناو بازنەی لە دایکبوونەوە و پیربوون.",
  "342": "ئەو خەڵکەی لە ناو داوی حەز و تەماحدا ئاڵاون، ڕێک وەک کەروێشکێکی گەمارۆدراو و ترساو لە قەفەسدا دەتلێنەوە. ئەوان بە کۆتوبەند و زنجیرەکان توند بەستراونەتەوە، و بۆ ماوەیەکی درێژخایەن، چەندین جار و بەردەوام دووچاری خەم و پەژارە دەبنەوە.",
  "343": "خەڵکی، کاتێک لە ناو داوی حەزدا ئاڵاون، وەک کەروێشکێکی دیل تۆقیون. کەواتە با ئەو ڕێبوارەی [بیکخو] کە ئارەزووی گەیشتن بە دۆخی بێ ئارەزوویی ڕەها [نیببانا] دەکات، حەز و تەماحی ناخی فڕێ بدات.",
  "344": "سەیری ئەو مرۆڤە بکەن! ئەو کەسەی کە سەرەتا بەبێ حەز [بۆ ژیانی باوی خێزانی] چێژی لە دارستانی [تەرکە دونیا و زاھید] دەبینی، و هەرچەندە لەو حەزە دنیاییانەش ڕزگاری ببوو، کەچی دیسانەوە غاری دایەوە بۆ ناو هەمان ماڵ و ژیانی کۆن. وەرن تەماشای بکەن! ئەو کەسەی ئازاد ببوو، چۆن دیسانەوە بە غار بۆ ناو هەمان کۆتوبەند و کۆیلایەتی دەگەڕێتەوە.",
  "345": "حەکیمەکان دەڵێن: ئەو بەستنەوە و کۆتوبەندانەی لە ئاسن، دار، یان پەت دروست دەکرێن زنجیری بەهێز نین؛ بەڵکوو شەیدابوونن بۆ گەوهەر، زێڕ و زیو، منداڵ و هاوسەر، خۆ بەستنەوەیەکی ئێجگار مەزنتر و توندترە.",
  "346": "داناکان دەڵێن: زنجیری ناخ [شەیدابوونی مادی] زۆر بەهێزە. مرۆڤ بەرەو خوارەوە پەلکێش دەکات، لولخواردووە، و کردنەوەی ئێجگار دژوارە. بەڵام حەکیمەکان ئەم کۆتوبەندەش دەپچڕێنن، و بەبێ هیچ خولیا و شەیدابوونێک واز لە جیهانی ماددی دەهێنن و دەستبەرداری چێژە هەستییەکان دەبن.",
  "347": "ئەو کەسانەی وا بە شەهوەت و ئارەزوو مەست بوون، دەگەڕێنەوە ناو لافاوی خولانەوە؛ ڕێک وەک چۆن جاڵجاڵۆکەیەک دەکەوێتەوە ناو ئەو داوەی کە خۆی چنیویەتی. حەکیمەکان ئەم داوەش دەبڕن و بەبێ هیچ خولیا و وابەستەییەک کۆچ دەکەن، کاتێک لە سەرجەم ژان و خەمەکان ڕزگاریان بووە.",
  "348": "دەستبەرداری ڕابردوو ببە. دەستبەرداری داهاتوو ببە. دەستبەرداری ئێستاش ببە [پێشەوە، دواوە، و ناوەڕاست]. کاتێک دەپەڕیتەوە بۆ ئەوبەری کەناری بوون، بە عەقڵێکەوە کە لە هەموو شتێک ئازاد بووە، مەهێڵە جارێکی تر بکەویتەوە ناو خولی لە دایکبوونەوە و پیربوون.",
  "349": "بۆ ئەو مرۆڤەی کە بەهۆی بیرکردنەوە [بەدەکانەوە] شڵەژاوە، ئەوەی کە شەهوەتێکی یەکجار زۆری هەیە و تەنها تێڕامان لەسەر شتە چێژبەخشەکان دەکات؛ حەز و تەماح لە ناخیدا سات بە سات زیاتر دەبێت. بە دڵنیاییەوە، ئەو کەسە زنجیرەکەی [مارا] لە دەوری خۆی توندتر دەکات.",
  "350": "بەڵام ئەو کەسەی کە چێژ لە دەستەمۆکردنی بیرکردنەوە [بەدەکان] دەبینێت، ئەوەی کە تێڕامان لەسەر 'سروشتی کاتی و ناپاکی' [جەستە] دەکات و هەمیشە هۆشیارە؛ تەنها ئەو کۆتایی بە [حەز و تەماح] دەهێنێت. ئەو زنجیرەکەی مارا دەپچڕێنێت.",
  "351": "ئەو کەسەی گەیشتووەتە ئامانج [کەناری ڕزگاری]، نەترسە، بێ حەز و تەماحە، خاڵییە لە کینە و شەهوەت، و دڕکەکانی ژیانی [وەهم و ئێش] بڕیوەتەوە. ئەم جەیستەیەی ئێستای، دواین جەیستەی دەبێت [و چیدی لە دایک نابێتەوە].",
  "352": "ئەو کەسەی کەناری گرتووە بەبێ حەز و دەست پێوەگرتن، ئەوەی خاوەن لێهاتووییە لە ڕیشەی وشەکان و چەمکەکاندا، ئەوەی ڕیزبەندی پیتەکان و پێکەوەبەستنیان بە باشی دەناسێت؛ تەنها ئەو شایستەی ئەوەیە پێی بگوترێت خاوەنی دواین جەستە، کەسێک لە داناییەکی قووڵ، و مرۆڤێکی مەزن.",
  "353": "من بەسەر هەموو شتێکدا سەرکەوتم، من بە هەموو شتێک دەزانم. لە هەموو شتێک جیا بوومەتەوە و دەستبەرداری هەموو شتێک بووم. بە تەواوی نوقمی دۆخی 'لە ناوبردنی حەز و تەماحم'. کاتێک خۆم بە تەنیایی درکم بە هەموو حەقیقەتێک کردووە، کێ بە مامۆستای خۆم بناسێنم؟",
  "354": "بەخشینی حەقیقەت، لە سەرجەم بەخشینەکانی تر باڵاترە. تامی حەقیقەت، لە سەرجەم تامەکان بەچێژترە. کەیفخۆشی بە حەقیقەت، لە سەرجەم خۆشییەکان بەرزترە. ئەو کەسەی کە حەز و تەماحی ناخی تێک دەشکێنێت، بەسەر سەرجەم خەم و ناسۆرییەکاندا سەردەکەوێت.",
  "355": "سەروەت و سامان مرۆڤی نەفام و گەمژە بەرەو لەناوچوون دەبات، بەڵام نەک ئەو کەسانەی کە لە گەڕانی کەناری ئەوبەردا وێڵن [نیببانا]. مرۆڤی نەزان بەهۆی تینوێتی بۆ کۆکردنەوەی سامان، خۆی لە ناو دەبات، ڕێک وەک چۆن زیان بە خەڵکانی تر دەگەیەنێت و ئەوانیش لە ناو دەبات.",
  "356": "گیای کێوی، مایەی لەناوچوونی کێڵگەکانن، شەهوەت و ئارەزووش خەوشی مرۆڤایەتین. کەواتە، ئەوەی پێشکەش دەکرێت بەو کەسانەی لە داوی شەهوەت ڕزگاریان بووە، بەرهەم و فەزیلەتێکی بێشومار و فراوان دەبەخشێت.",
  "357": "گیای کێوی، خەوشی کێڵگەکانن، کینە و ڕقیش خەوشی مرۆڤایەتین. کەواتە، ئەوەی پێشکەش دەکرێت بەو کەسانەی لە داوی ڕق پاک بوونەتەوە، بەرهەمێکی یەکجار پڕ فەزیلەت دەبەخشێت.",
  "358": "گیای کێوی، خەوشی کێڵگەکانن، وەهم و نەزانیش خەوشی مرۆڤایەتین. کەواتە، ئەوەی پێشکەش دەکرێت بەو کەسانەی لە داوی وەهم ڕزگاریان بووە، بەرهەمێکی یەکجار مەزن دەبەخشێت.",
  "359": "گیای کێوی، خەوشی کێڵگەکانن، حەز و تەماحیش خەوشی مرۆڤایەتین. کەواتە، ئەوەی پێشکەش دەکرێت بەو کەسانەی کە ناخیان لە حەز و تینوێتی پاک بووەتەوە، فراوانترین و بەپیتترین بەرهەمی ڕۆحی دەبەخشێت.",
  "chap25": "ڕێبوار، دەروێشی گەڕۆک",
  "360": "بەنرخە پارێزگاری و کۆنتڕۆڵکردنی چاو؛ بەنرخە پارێزگاریی گوێ؛ بەنرخە پارێزگاریی لووت؛ بەنرخە پارێزگاریی زمان لە چەوتی.",
  "361": "بەنرخە پارێزگاری لە ڕەفتاردا؛ بەنرخە پارێزگاری لە ئاخاوتندا؛ بەنرخە پارێزگاریی عەقڵ؛ بەنرخە پارێزگاری لە هەموو شتێکدا. ئەو ڕێبوارەی [بێکهو] کە لە هەموو ڕوویەکەوە کۆنتڕۆڵی ناخی دەکات، لە خەم و ناسۆر ڕزگاری دەبێت.",
  "362": "ئەو کەسەی کە دەست، پێ، قسە، و هۆشیاریی [سەری] لەژێر ڕکێفدایە؛ ئەوەی چێژ لە تێڕامان [مێدیتەیشن] دەبینێت و هێمنە؛ ئەوەی بە تەنیایی ڕاهاتووە و قانعە، ئەوا خەڵکی بە [بێکهو] [ڕێبواری حەقیقەت] ناوی دەبەن.",
  "363": "ئەو ڕێبوارەی کۆنتڕۆڵی زمانی دەکات، بە داناییەوە دەدوێت، فیز بەسەر کەسدا لێ نادات، و مانا و دەقە پیرۆزەکان ڕوون دەکاتەوە؛ بە ڕاستی ئاخاوتنی ئەو یەکجار شیرین و کاریگەرە.",
  "364": "ئەو ڕێبوارەی لە ناو حەقیقەتدا [دھاما] دەژی، کەیفخۆشە بە حەقیقەت، تێڕامان لەسەر حەقیقەت دەکات و بە باشی حەقیقەتی لەبیرە، هەرگیز لەو حەقیقەتە باڵایە لاناچێت و ناکەوێت.",
  "365": "با سووکایەتی بەو ڕۆزی و بەخششانە نەکات کە پێی گەیشتووە، و نابێت بە چاوپیسی و بەغیلییەوە بڕوانێتە بەرهەمی خەڵکی تر. ئەو ڕێبوارەی بەغیلی بە [دەستکەوتی] ئەوانی تر دەبات، هەرگیز ناگاتە قۆناغی سەرنجدانی قووڵ و خەڵوەت.",
  "366": "تەنانەت ئەگەر کەمێکیشی پێ بگات، ئەگەر ڕێبوارێک سووکایەتی بە دەستکەوتی خۆی نەکات، تەنانەت خوداوەندەکانیش ستایشی دەکەن، چونکە بژێویی ژیانی پاکە و تەمبەڵ و سست نییە.",
  "367": "ئەو کەسەی کە هیچ تێڕوانینێکی خۆپەرستانەی بۆ 'من' و 'هی من' نییە بەرامبەر بە عەقڵ و جەستەی خۆی، و خەم بۆ شتێک ناخوات کە نییەتی؛ بە ڕاستی تەنها ئەو شایستەی ناوی 'بێکهو'ـە.",
  "368": "ئەو ڕێبوارەی لە ناو سۆز و خۆشەویستیی بێ مەرجدا دەژی، و دڵشادە بە فێرکارییەکانی بوودا، دەگاتە ئەو دۆخە لە ئاشتی و بەختەوەریی ڕەها، کە دۆخی کپکردنەوەی سەرجەم شتە کاتی و مەرجدارەکانە [نیببانا].",
  "369": "ئەی زاھید [ڕێبوار]! ئەم بەلەمە لە ئاو خاڵی بکەرەوە؛ کاتێک سووک دەبێت، زۆر بە خێرایی و ئارامی بەسەر ئاوەکەدا دەڕوات. بە هەمان شێوە، کاتێک ناخی خۆت لە قورسیی شەهوەت و کینە پاک دەکەیتەوە، زۆر بە ئاسانی بەسەر کێشە و ناخۆشییەکانی ژیاندا تێپەڕ دەبیت و دەگەیتە کەناری ئازادیی ڕەها [نیببانا].",
  "370": "پێنج شت ببڕە، پێنج شت فڕێ بدە، و پێنج شتی تر لە ناخی خۆتدا پەرە پێ بدە. ئەو ڕێبوارەی کە لەم پێنج کۆت و بەندە تێپەڕیوە، پێی دەگوترێت [پەڕیوەتەوە لە لافاو].",
  "371": "ئەی زاھید [ڕێبوار]، هەمیشە خەریکی تێڕامان و هۆشیاری بە و غافڵ مەبە! مەهێڵە عەقڵت بەدوای چێژە کاتی و ماددییەکاندا تێک بچێت، تا وەک کەسێکی بێباک نەبیت کە بە دەستی خۆی تۆپەڵێک ئاسنی گەرم و تواوە قووت دەدات؛ چونکە کاتێک ناخت بەهۆی ئەو چێژانەوە دەسووتێت و وێران دەبێت، ئیتر هاوارکردن و گریان دادت نادات کە بڵێیت: 'ئای لەم ژان و ناسۆرە'.",
  "372": "هیچ خەڵوەت و سەرنجدانێکی قووڵ لەو کەسەدا نییە کە دانایی کەمە، بە هەمان شێوە هیچ داناییەکیش لەو کەسەدا نییە کە خاوەنی سەرنجدان و ڕامان نییە. بەڵام لە ناخی هەر کەسێکدا هەم سەرنجدان و هەم دانایی پێکەوە کۆ ببنەوە، ئەو کەسە بە ڕاستی لە ئامادەبوونی دۆخی ئازادیدایە [نیببانا].",
  "373": "ئەو ڕێبوارەی کە پەنا دەباتە بەر شوێنێکی تەنیا مەنزڵ، ئەوەی عەقڵی خۆی هێمن کردووەتەوە و بە ڕوونی درک بە یاسای گەردوون دەکات، چێژ لە خۆشییەک دەبینێت کە لە سەرووی خۆشیی مرۆڤە ئاساییەکانەوەیە.",
  "374": "هەر کاتێک ئەو تێڕامان لەسەر سەر هەڵدان و داڕمانی پێکهاتەکانی بوون بکات، کەیفخۆشی و شادومانی دەچێژێت. بۆ 'ئەوانەی حەقیقەت دەناسن'، ئەم تێڕامانە ڕێگای نەمر بوونە.",
  "375": "لێرەدا، ئەمە دەبێتە سەرەتای کار بۆ ڕێبوارێکی دانا: کۆنتڕۆڵی هەستەکان، قەناعەت و ڕەزامەندی، پابەندبوون بە یاسا و ڕەوشتە بنەڕەتییەکان، و هاوڕێیەتی کردن لەگەڵ دۆستانی دڵسۆز و چالاک کە بژێوییان پاکە.",
  "376": "با مرۆڤێکی گەرموگوڕ و دۆستانە بێت لە ڕەفتاریدا، و خاوەن ڕەوشتێکی بەرز بێت؛ بەمەش ناخی پڕ دەبێت لە شادی، و کۆتایی بە سەرجەم ئێش و ئازارەکانی دەهێنێت.",
  "377": "وەک چۆن دەوەنی گوڵە یاسەمین، گەڵا و گوڵە سیسبووەکانی خۆی دەوەرێنێت؛ بە هەمان شێوەش، ئەی ڕێبواران، ئێوەش دەبێت بە تەواوی شەهوەت و کینە لە ناخی خۆتاندا بوەرێنن و فڕێی بدەن.",
  "378": "ئەو ڕێبوارەی لە جەستەدا هێمنە، لە قسەدا هێمنە، لە عەقڵدا هێمنە، خاوەن دیسپلینێکی ڕێکخراوە، و سەرجەم حەزە دنیاییەکانی لە ناخی خۆیدا ڕشاندووەتەوە؛ بە ڕاستی پێی دەگوترێت [مرۆڤی ئاشتیخواز].",
  "379": "بە هۆشیاریی خۆت، لۆمەی خۆت بکە. بە عەقڵی خۆت، پشکنین بۆ ناخی خۆت بکە. کاتێک بە هۆشیارییەوە پاسەوانیی خۆت دەکەیت، ئەی ڕێبوار، بە بەختەوەرییەوە دەژیت.",
  "380": "ناخی مرۆڤ، بە ڕاستی پارێزەری ناخی خۆیەتی. ناخی مرۆڤ، بە ڕاستی پەناگەی خۆیەتی. کەواتە، کۆنتڕۆڵی ناخی خۆت بکە، ڕێک وەک چۆن بازرگانێک کۆنتڕۆڵی ئەسپێکی ڕەسەن و یاخی دەکات.",
  "381": "پڕ لە شادی، پڕ لە متمانە بە فێرکارییەکانی بوودا، ڕێبوارەکە دەگاتە دۆخی ئاشتیی ڕەها، کپبوونەوەی شتە کاتییەکان، و گەورەترین بەختەوەریی باڵا.",
  "382": "ئەو ڕێبوارەی کە هێشتا گەنجە و خۆی تەرخان دەکات بۆ فێرکارییەکانی بوودا، ئەم جیهانە ڕووناک دەکاتەوە، ڕێک وەک مانگ کاتێک لە پشت هەورێکی تاریکەوە دێتە دەرەوە و دەدرەوشێتەوە.",
  "chap26": "مرۆڤی دانا",
  "383": "تێبکۆشە و بە توندی بەرەنگاری لافاوی حەز و تەماح ببەرەوە؛ ئەی مرۆڤی دانا، سەرجەم خولیا و ئارەزووە کاتییەکانی هەست پێکردن فڕێ بدە. کاتێک بە قووڵی تێدەگەیت کە هەموو شتە ماددی و مەرجدارەکانی ئەم جیهانە بەرەو لەناوچوون دەچن، ئەو کاتە خۆت لە ناخەوە دەبیتە 'دۆزەرەوە و خاوەن ناسیاوی' ئەو حەقیقەتە هێمن و نەمرە [نیببانا].",
  "384": "کاتێک مرۆڤی دانا لە دوو دۆخدا [کە هەم تێڕامانی قووڵە و هەم بینینی ڕاستییەکانە] دەگاتە کەناری ئەوبەر، ئەوا سەرجەم کۆت و بەندەکانی ئەو 'کەسە بەئاگایە' لا دەچن و نامێنن.",
  "385": "ئەو کەسەی کە نە کەناری ئەمبەر [جیهانی ماددی] و نە کەناری ئەوبەر [جیهانی ڕۆحی]، و نە هیچ کامیان کۆتی ناکەن، ئەو کەسەی بێباکە لە خەم و ئازادە لە وابەستەبوون، تەنها ئەو بە 'دانا' ناودەبەم.",
  "386": "ئەو کەسەی کاتەکانی بە تێڕامان دەباتەسەر، بێگەرد و گۆشەگیرە، ئەرکی سەرشانی خۆی بەجێهێناوە و لە خەوشەکان پاک بووەتەوە، و گەیشتووەتە باڵاترین ئامانج، تەنها ئەو بە 'دانا' ناودەبەم.",
  "387": "ڕۆژ بە هۆی خۆرەوە دەدرەوشێتەوە؛ شەویش بە هۆی مانگەوە ڕووناکە. پادشای جەنگاوەر بە هۆی قەڵغان و زرێپۆشەکەیەوە دەبریسکێتەوە. مرۆڤی داناش لە کاتی تێڕاماندا دەدرەوشێتەوە. بەڵام بوودا لە تەواوی ڕۆژ و شەودا بە شکۆ و مەزنیی خۆی شەکاوەیە.",
  "388": "بە هۆی ئەوەی خراپەی فڕێداوە، پێی دەگوترێت: 'دانا'؛ بە هۆی ئەوەی لە ناخدا بە ئاشتی دەژی، پێی دەگوترێت: 'سەمانا - گۆشەگیر'؛ و بە هۆی ئەوەی ناخی لە گەندەڵی پاک کردووەتەوە، پێی دەگوترێت: 'پاباجیتا - تەرکی دونیاکەر'.",
  "389": "نابێت کەس لە مرۆڤی دانا بدات، و ناشبێت مرۆڤی دانا ڕق و توڕەیی خۆی بڕێژێت بەسەر ئەو کەسەی کە لێی داوە. شەرمەزاری بۆ ئەو کەسەی لە دانایەک دەدات! و شەرمەزاریی زیاتریش بۆ ئەو دانایەی کە کۆنتڕۆڵی خۆی لە دەست دەدات و بە توڕەیی وەڵام دەداتەوە.",
  "390": "بۆ مرۆڤی دانا، ئەم [تۆڵە نەسەندنەوە و وەڵام نەدانەوەیە بە خراپە] سوودێکی یەکجار گەورەی هەیە. کاتێک عەقڵ لە شتە کاتی و دڵخوازەکان دادەبڕێت، و هەر کاتێک ئارەزووی ئازاردانی خەڵکی لە ناخدا دەمرێت، تەنها لەو کاتەدا خەم و ناسۆر کپ دەبێتەوە.",
  "391": "ئەو کەسەی کە هیچ خراپەیەک لە ڕێگەی جەستە، قسە، یان عەقڵییەوە ئەنجام نادات، و لەم سێ ڕووەوە خۆپێوەگر و بەئاگایە، تەنها ئەو بە 'دانا' ناودەبەم.",
  "392": "ئەگەر لە هەر کەسێکەوە فێرکاری و دەقەکانی بوودای ڕووناکبووەوە فێر بوویت، پێویستە بەوپەڕی دڵسۆزی و ڕێزەوە سەیری بکەیت، ڕێک وەک چۆن پیاوێکی ئاینیی کۆن ڕێز لە ئاگری پیرۆزی قوربانی گرتووە.",
  "393": "مرۆڤ نە بە قژی ئاڵۆز و ڕستراو، نە بە ناوبانگی بنەماڵە، و نە بە بنەچە و لەدایکبوون نابێتە 'دانا'. بەڵکوو هەر کەسێک ڕاستگۆیی و دادپەروەری لە ناخیدا هەبێت، ئەو پاکە و تەنها ئەو 'دانایە'.",
  "394": "ئەی مرۆڤی کەم ئەقڵ، قژی کڵۆکڵۆ و ئاڵۆزت بۆ چی باشە؟ جلوبەرگی پێستی ئاسکت بۆ چ مەبەستێکە؟ کاتێک ناخت پڕە لە حەز و شەهوەت، بەڵام ڕووکەشت بە جوانی دەڕازێنیتەوە!",
  "395": "ئەو کەسەی کە جلی کۆن و فڕێدراو دەپۆشێت، جەستەی لاوازە و دەمارەکانی پێستی دیارن، و بە تەنیایی لە ناو دارستان و سروشتدا تێڕامان دەکات، تەنها ئەو بە 'دانا' ناودەبەم.",
  "396": "من بە کەسێک ناڵێم 'دانا' تەنها لەبەر ئەوەی لە زێد و پشتی دایک و باوکێکی خانەدان هاتووەتە دونیاوە. ئەو کەسە ئەگەر هێشتا کۆت و بەندی دونیای پێوە بێت، تەنها دەمڕاست و زمانلووسێکە. بەڵام ئەو کەسەی لە هەموو بەستنەوە و وابەستەبوونێک ئازادە، تەنها ئەو بە 'دانا' ناودەبەم.",
  "397": "ئەو کەسەی سەرجەم کۆتوبەندەکانی بڕیوە، لە هیچ ناخۆشییەکدا نالەرزێت، لە گرێکان تێپەڕیوە و بە تەواوی ئازادە، تەنها ئەو بە 'دانا' ناودەبەم.",
  "398": "ئەو کەسەی کە پەتکی 'ڕق و کینە'ی پچڕاندووە، قایشی 'حەز و تەماح'ی بڕیوە، و تەنافی 'بیروباوەڕە چەوتەکانی' هەڵوەشاندووەتەوە؛ ئەو کەسەی کە بە تەواوی کۆسپە گەورەکەی بەردەم هۆشیاری [کە نەزانی و غەفڵەتە] تێکشکاندووە و گەیشتووەتە ڕووناکبوونی ڕەها، تەنها ئەو بە 'دانا' ناودەبەم.",
  "399": "ئەو کەسەی بەبێ توڕەیی، بەرگەی تانەوتەشەر، لێدان و سزادان دەگرێت، و گەورەترین هێز و سوپای پاڵپشتی بریتییە لە 'ئارامگرتن'، تەنها ئەو بە 'دانا' ناودەبەم.",
  "400": "ئەو کەسەی توڕە نابێت، پابەندە بە بەڵینەکانی، خاوەن ڕەوشتە، تینوێتی مادی لە ناخیدا نەماوە، کۆنتڕۆڵی دەروونی لایە و ئەم جەستەیەی ئێستای دوایین جەستەی دەبێت لەم سەر زەمینەدا [چیتر نایەتەوە ناو خولی لەدایکبوونەوە]، تەنها ئەو بە 'دانا' ناودەبەم.",
  "401": "ڕێک وەک دڵۆپە ئاو بەسەر گەڵای لۆتۆسەوە، یان وەک دەنکە خەردەل لەسەر نووکی دەرزی، ئەو کەسەی کە بە چێژی هەستە کاتییەکانەوە ناچەسپێت، تەنها ئەو بە 'دانا' ناودەبەم.",
  "402": "ئەو کەسەی لەم جیهانەدا درک بە کۆتاییهاتنی ژان و ناسۆرەکانی دەکات، بارە قورسەکەی دەروونی داناوە و ڕزگاری بووە، تەنها ئەو بە 'دانا' ناودەبەم.",
  "403": "ئەو کەسەی زانیارییەکانی قووڵن، ژیرە، ڕێگای ڕاست و چەوت لە یەکتر جیا دەکاتەوە، و گەیشتووەتە باڵاترین مەنزڵ، تەنها ئەو بە 'دانا' ناودەبەم.",
  "404": "ئەو کەسەی نە لەگەڵ خەڵکی خاوەن ماڵ و دنیاییدا تێکەڵە و نە لەگەڵ بێماڵان و گۆشەگیرەکاندا، بەبێ شوێنێکی دیاریکراو دەگەڕێت و هیچ حەزێکی نییە، تەنها ئەو بە 'دانا' ناودەبەم.",
  "405": "ئەو کەسەی کە چەک و داری ئازاردانی داناوە لە مامەڵەکردنیدا لەگەڵ زیندەوەراندا، چ لاواز بن یان بەهێز، نە زیانیان پێ دەگەیەنێت و نە دەیانکوژێت، تەنها ئەو بە 'دانا' ناودەبەم.",
  "406": "ئەو کەسەی لە ناو خەڵکی دوژمنکاردا دۆستانەیە، لە ناو توندوتیژەکاندا هێمنە، و لە ناو خەڵکە دڵبەستە و چاوچنۆکەکاندا بێوەبەست و ئازادە، تەنها ئەو بە 'دانا' ناودەبەم.",
  "407": "ئەو کەسەی کە شەهوەت، کینە، فیز، و غەیبەت لە ناخیدا وەریون، ڕێک وەک وەرینی دەنکە خەردەلێک لەسەر نووکی دەرزییەک، تەنها ئەو بە 'دانا' ناودەبەم.",
  "408": "ئەو کەسەی وتی نەرم، فێرکاری و ڕاستگۆیانە دەردەبڕێت، و بە قسەکانی ئازاری دڵی هیچ کەسێک نادات، تەنها ئەو بە 'دانا' ناودەبەم.",
  "409": "ئەو کەسەی لەم جیهانەدا هیچ شتێک بۆ خۆی نابات کە پێی نەبەخشرابێت، چ درێژ بێت یان کورت، بچووک بێت یان گەورە، جوان بێت یان ناشرین، تەنها ئەو بە 'دانا' ناودەبەم.",
  "410": "ئەو کەسەی کە هیچ خولیا و ئاواتێکی نییە بۆ ئەم جیهانە و بۆ جیهانی داهاتووش، بێ حەز و ڕزگاربووە، تەنها ئەو بە 'دانا' ناودەبەم.",
  "411": "ئەو کەسەی کە ئاواتی نەماوە، بەهۆی زانیارییەکەیەوە لە گومان ڕزگاری بووە، و پێگەیەکی قایمی لە دۆخی نەمر و هێمندا [نیببانا] دۆزیوەتەوە، تەنها ئەو بە 'دانا' ناودەبەم.",
  "412": "لێرەدا، ئەو کەسەی کە لە هەردوو چەمکی [باشە و خراپەی ڕووکەش] و لە تێکەڵاوبوونی دونیایی تێپەڕیوە، بێخەمە، بێگەردە و پاکە، تەنها ئەو بە 'دانا' ناودەبەم.",
  "413": "ئەو کەسەی وەک مانگی چواردە بێ پەڵەیە، پاک، ئارام و بێ ژاوەژاوە، و تینوێتیی لەدایکبوونەوەی لە ناخدا کوژاندووەتەوە، تەنها ئەو بە 'دانا' ناودەبەم.",
  "414": "ئەو کەسەی لەم زۆنگاوە، لەم ڕێگا سەختە، و لە دەریای پڕ لە شەپۆلی ژیان [سامسارا] و وەهم تێپەڕیوە، ئەوەی پەڕیوەتەوە بۆ کەناری ئارامی، تێڕامان دەکات، بێ حەز و بێگومانە، و بە هۆی وابەستەنەبوونی بە هیچ شتێکەوە گەیشتووەتە ئازادی نیببانا، تەنها ئەو بە 'دانا' ناودەبەم.",
  "415": "ئەو کەسەی لەم جیهانەدا دەستبەرداری چێژە هەستییەکان دەبێت، ژیانی دنیایی جێدەهێڵێت و دەبێتە گەڕۆکێکی بێماڵ، و کۆتایی بە ئارەزووی بوون دەهێنێت، تەنها ئەو بە 'دانا' ناودەبەم.",
  "416": "ئەو کەسەی لەم جیهانەدا دەستبەرداری تینوێتیی ناخ [تەماح] دەبێت، ژیانی دنیایی خەڵک پشتگوێ دەخات و دەبێتە گەڕۆکێکی بێماڵ، و تەماح و خولیای بوون لە ناخیدا دەمرێنێت، تەنها ئەو بە 'دانا' ناودەبەم.",
  "417": "ئەو کەسەی کە بەستەرە مرۆییەکان فڕێ دەدات و لە کۆتوبەندە ئاسمانییەکانیش باڵاتر دەبێت، و بە تەواوی لە هەموو جۆرە پەت و بەستنەوەیەک ڕزگاری بووە، تەنها ئەو بە 'دانا' ناودەبەم.",
  "418": "ئەو کەسەی کە وازی لە حەزکردن و ڕقلێبوون [پەسەندکردن و نەکردن] هێناوە، ناخی فێنک بووەتەوە و بێخەوشە، جیهانی ناخی خۆی کۆنتڕۆڵ کردووە و کۆشش دەکات، تەنها ئەو بە 'دانا' ناودەبەم.",
  "419": "ئەو کەسەی کە بە هەموو شێوازێک دەزانێت زیندەوەران چۆن دەمرن و چۆن سەره‌نوێ لە دایک دەبنەوە، ئەوەی وابەستە نییە، بە ڕێگای دروستدا ڕۆیشتووە و بەئاگا هاتووە، تەنها ئەو بە 'دانا' ناودەبەم.",
  "420": "ئەو کەسەی کە چارەنووس و مەنزڵگەکەی نە لە لایەن خوداوەندەکان، نە فریشتەکان [گانداباکان] و نە مرۆڤەکانەوە نازانرێت، ئەوەی سەرجەم گەندەڵییەکانی دەروونی تێکشکاندووە و لە شەهوەت دوور کەوتووەتەوە [ئەراهانت]، تەنها ئەو بە 'دانا' ناودەبەم.",
  "421": "ئەو کەسەی کە هیچ دڵبەستەییەکی بە پێکهاتەکانی بوونەوە نییە، چ لە ڕابردوو، چ لە ئێستا و چ لە داهاتوودا، و بێگرتن و بێچاوچنۆکی دەژی، تەنها ئەو بە 'دانا' ناودەبەم.",
  "422": "ئەو مرۆڤە نەترس، نەجیبزادە، پاڵەوان، زانا گەورە، سەرکەوتوو، بێحەز، و پاککەرەوەی ناخ، ئەو کەسەی بە تەواوی هۆشیار بووەتەوە، تەنها ئەو بە 'دانا' ناودەبەم.",
  "423": "ئەو زانایەی کە مەنزڵگە و ژیانەکانی پێشووی خۆی دەناسێت، دۆخی بەختەوەری و دۆخی دۆزەخی [ئازار] دەبینێت، گەیشتووەتە کۆتایی خولی لەدایکبوونەکان، بە داناییەکی باڵاوە ناخی خۆی تەواو کردووە، ژیانی پیرۆزی گەیاندووەتە کەنار، و کۆتایی بە سەرجەم خولیا و شەهوەتەکان هێناوە، تەنها ئەو بە 'دانا' ناودەبەم."
};
